use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub category: String,
    pub amount: i32,
}

pub fn category_report(entries: &[Entry]) -> Vec<String> {
    let mut totals: BTreeMap<String, i32> = BTreeMap::new();

    for entry in entries {
        *totals.entry(entry.category.clone()).or_insert(0) += entry.amount;
    }

    let mut rows: Vec<(String, i32)> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(&b.0));

    rows.into_iter()
        .map(|(category, total)| format!("{}:{}", category, total))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn e(category: &str, amount: i32) -> Entry {
        Entry {
            category: category.to_string(),
            amount,
        }
    }

    #[test]
    fn sorts_by_total_desc_then_category_name() {
        let entries = vec![
            e("books", 10),
            e("games", 15),
            e("books", 15),
            e("tools", 25),
            e("art", 25),
        ];

        assert_eq!(
            category_report(&entries),
            vec!["art:25", "books:25", "tools:25", "games:15"]
        );
    }

    #[test]
    fn ignores_non_positive_entries_and_drops_non_positive_totals() {
        let entries = vec![
            e("books", 10),
            e("books", -3),
            e("games", 0),
            e("garden", -2),
            e("art", 5),
            e("art", 5),
        ];

        assert_eq!(category_report(&entries), vec!["books:10", "art:10"]);
    }
}

