pub fn collect_active_ids(rows: &[&str]) -> Vec<u32> {
    rows.iter()
        .filter_map(|row| {
            let (status, id) = row.split_once(':')?;
            if status != "active" {
                return None;
            }
            id.parse::<u32>().ok()
        })
        .filter(|id| *id > 0)
        .collect()
}

