        assert_eq!(collect_active_ids(&rows), vec![7, 12]);
    }

    #[test]
    fn ignores_whitespace_padded_status() {
        let rows = [" active:4", "active:5", "active:2 "];
        assert_eq!(collect_active_ids(&rows), vec![5, 2]);
    }
}

