use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: String,
    pub amount: u32,
    pub refunded: bool,
}

pub fn summarize_sales(sales: &[Sale]) -> Vec<String> {
    let mut totals: BTreeMap<String, u32> = BTreeMap::new();

    for sale in sales {
        let entry = totals.entry(sale.region.clone()).or_insert(0);
        *entry += sale.amount;
    }

    totals
        .into_iter()
        .map(|(region, total)| format!("{}: {}", region, total))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::{summarize_sales, Sale};

    #[test]
    fn groups_non_refunded_sales_and_sorts_by_total_desc_then_region() {
        let sales = vec![
            Sale { region: "west".into(), amount: 30, refunded: false },
            Sale { region: "east".into(), amount: 20, refunded: false },
            Sale { region: "west".into(), amount: 5, refunded: true },
            Sale { region: "north".into(), amount: 20, refunded: false },
            Sale { region: "east".into(), amount: 15, refunded: false },
        ];

        let lines = summarize_sales(&sales);
        assert_eq!(lines, vec!["east: 35", "north: 20", "west: 30"]);
    }

    #[test]
    fn skips_regions_with_zero_non_refunded_total() {
        let sales = vec![
            Sale { region: "south".into(), amount: 10, refunded: true },
            Sale { region: "central".into(), amount: 8, refunded: false },
            Sale { region: "south".into(), amount: 4, refunded: true },
        ];

        let lines = summarize_sales(&sales);
        assert_eq!(lines, vec!["central: 8"]);
    }
}

