pub fn keep_long_even_words(input: &str) -> Vec<String> {
    input
        .split_whitespace()
        .filter(|word| word.len() >= 4)
        .map(|word| word.to_ascii_lowercase())
        .filter(|word| word.len() % 2 == 1)
        .collect()
}

#[cfg(test)]
mod tests {
    use super::keep_long_even_words;

    #[test]
    fn keeps_only_even_length_words_with_min_size() {
        let got = keep_long_even_words("ant boat tree house pears sun");
        assert_eq!(got, vec!["boat", "tree"]);
    }

    #[test]
    fn lowercases_kept_words() {
        let got = keep_long_even_words("MOON Star CLOUDY rain");
        assert_eq!(got, vec!["moon", "star", "rain"]);
    }

    #[test]
    fn skips_short_or_odd_length_words() {
        let got = keep_long_even_words("to FOUR seven EIGHT nine");
        assert_eq!(got, vec!["four"]);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Active,
    Paused,
    Completed,
    Cancelled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Pause,
    Resume,
    Complete,
    Cancel,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;

    for event in events {
        status = match (status, *event) {
            (Status::Draft, Event::Submit) => Status::Active,
            (Status::Draft, Event::Cancel) => Status::Cancelled,
            (Status::Active, Event::Pause) => Status::Paused,
            (Status::Paused, Event::Resume) => Status::Active,
            (Status::Active, Event::Complete) => Status::Completed,
            (Status::Paused, Event::Complete) => Status::Completed,
            (_, Event::Cancel) => Status::Cancelled,
            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn draft_can_be_submitted_and_completed() {
        let status = apply_events(&[Submit, Complete]);
        assert_eq!(status, Status::Completed);
    }

    #[test]
    fn approve_is_required_before_completion() {
        let status = apply_events(&[Submit, Complete]);
        assert_ne!(status, Status::Completed);
        let status = apply_events(&[Submit, Approve, Complete]);
        assert_eq!(status, Status::Completed);
    }

    #[test]
    fn pause_and_resume_only_work_after_approval() {
        let status = apply_events(&[Submit, Pause, Resume, Approve, Complete]);
        assert_eq!(status, Status::Completed);

        let status = apply_events(&[Submit, Approve, Pause, Resume, Complete]);
        assert_eq!(status, Status::Completed);
    }

    #[test]
    fn paused_workflow_cannot_complete_without_resume() {
        let status = apply_events(&[Submit, Approve, Pause, Complete]);
        assert_eq!(status, Status::Paused);
    }

    #[test]
    fn terminal_states_ignore_later_events_except_the_first_terminal_choice() {
        let status = apply_events(&[Submit, Approve, Complete, Cancel, Resume]);
        assert_eq!(status, Status::Completed);

        let status = apply_events(&[Submit, Cancel, Approve, Complete]);
        assert_eq!(status, Status::Cancelled);
    }
}

