pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;
    let mut approved = false;

    for event in events {
        status = match (status, *event) {
            (Status::Completed | Status::Cancelled, _) => status,
            (Status::Draft, Event::Submit) => Status::Active,
            (Status::Draft, Event::Cancel) => Status::Cancelled,
            (Status::Active, Event::Approve) => {
                approved = true;
                Status::Active
            }
            (Status::Active, Event::Pause) if approved => Status::Paused,
            (Status::Paused, Event::Resume) => Status::Active,
            (Status::Active, Event::Complete) if approved => Status::Completed,
            (_, Event::Cancel) => Status::Cancelled,
            _ => status,
        };
    }

    status
}

