fn apply(t: &mut Ticket, e: &Event) {
    match *e {
        Event::Assign { user, .. } => {
            if t.status != Status::Closed {
                t.assignee = Some(user);
                t.status = Status::InProgress;
            }
        }
        Event::Unassign { .. } => {
            if t.status != Status::Closed {
                t.assignee = None;
                t.status = Status::Open;
            }
        }
        Event::Close { .. } => {
            if t.assignee.is_some() {
                t.status = Status::Closed;
            }
        }
        Event::Reopen { .. } => {
            if t.status == Status::Closed {
                t.status = if t.assignee.is_some() {
                    Status::InProgress
                } else {
                    Status::Open
                };
            }
        }
        Event::Create { .. } => {}
    }
}

