struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let requests = vec![
        Booking { id: "A", start: 60, end: 120 },
        Booking { id: "B", start: 120, end: 180 },
        Booking { id: "C", start: 30, end: 60 },
        Booking { id: "D", start: 200, end: 190 },
        Booking { id: "E", start: 180, end: 240 },
        Booking { id: "F", start: 240, end: 300 },
        Booking { id: "G", start: 0, end: 30 },
        Booking { id: "H", start: 299, end: 360 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut accepted_ids: Vec<&str> = Vec::new();
    let mut rejected: Vec<String> = Vec::new();

    for req in requests {
        if req.start >= req.end {
            rejected.push(format!("{}:invalid", req.id));
            continue;
        }

        let mut blocked_by: Option<&str> = None;
        for existing in &accepted {
            if overlaps(&req, existing) {
                blocked_by = Some(existing.id);
                break;
            }
        }

        if let Some(id) = blocked_by {
            rejected.push(format!("{}:conflict with {}", req.id, id));
        } else {
            accepted_ids.push(req.id);
            accepted.push(req);
        }
    }

    println!("accepted: {}", accepted_ids.join(","));
    println!("rejected: {}", rejected.join(","));
    println!("slots_used={}", accepted.len());
}

