use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Resolved => "Resolved",
            Status::Closed => "Closed",
        }
    }
}

#[derive(Clone)]
struct Ticket {
    id: &'static str,
    status: Status,
    owner: Option<&'static str>,
    blocked: bool,
    resolved: bool,
}

enum Event {
    Assign(&'static str),
    Start,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
}

fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Assign(owner) => {
            ticket.owner = Some(owner);
        }
        Event::Start => {
            ticket.status = Status::InProgress;
            ticket.blocked = false;
        }
        Event::Block => {
            ticket.status = Status::Blocked;
            ticket.blocked = true;
        }
        Event::Unblock => {
            ticket.blocked = false;
            ticket.status = Status::New;
        }
        Event::Resolve => {
            ticket.resolved = true;
            ticket.status = Status::Resolved;
        }
        Event::Close => {
            ticket.status = Status::Closed;
        }
        Event::Reopen => {
            ticket.status = Status::New;
        }
    }
}

fn main() {
    let mut tickets = BTreeMap::new();
    tickets.insert(
        "A",
        Ticket {
            id: "A",
            status: Status::New,
            owner: None,
            blocked: false,
            resolved: false,
        },
    );
    tickets.insert(
        "B",
        Ticket {
            id: "B",
            status: Status::New,
            owner: None,
            blocked: false,
            resolved: false,
        },
    );
    tickets.insert(
        "C",
        Ticket {
            id: "C",
            status: Status::New,
            owner: None,
            blocked: false,
            resolved: false,
        },
    );
    tickets.insert(
        "D",
        Ticket {
            id: "D",
            status: Status::New,
            owner: None,
            blocked: false,
            resolved: false,
        },
    );

    let log = vec![
        ("A", Event::Assign("alice")),
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Assign("bob")),
        ("B", Event::Start),
        ("B", Event::Resolve),
        ("B", Event::Reopen),
        ("B", Event::Assign("carol")),
        ("B", Event::Start),
        ("C", Event::Assign("dana")),
        ("C", Event::Start),
        ("C", Event::Block),
        ("D", Event::Assign("erin")),
        ("D", Event::Start),
        ("D", Event::Resolve),
        ("D", Event::Reopen),
        ("D", Event::Start),
        ("D", Event::Resolve),
        ("D", Event::Close),
    ];

    for (id, event) in log {
        let ticket = tickets.get_mut(id).unwrap();
        apply(ticket, event);
    }

    for ticket in tickets.values() {
        println!(
            "{}: {} owner={} resolved={} blocked={}",
            ticket.id,
            ticket.status.as_str(),
            ticket.owner.unwrap_or("-"),
            ticket.resolved,
            ticket.blocked
        );
    }
}

