fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Assign(owner) => {
            ticket.owner = Some(owner);
        }
        Event::Start => {
            if ticket.owner.is_some() {
                ticket.status = Status::InProgress;
                ticket.blocked = false;
            }
        }
        Event::Block => {
            if matches!(ticket.status, Status::InProgress) {
                ticket.status = Status::Blocked;
                ticket.blocked = true;
            }
        }
        Event::Unblock => {
            if ticket.blocked {
                ticket.blocked = false;
                ticket.status = Status::InProgress;
            }
        }
        Event::Resolve => {
            if matches!(ticket.status, Status::InProgress) && !ticket.blocked {
                ticket.resolved = true;
                ticket.status = Status::Resolved;
            }
        }
        Event::Close => {
            if ticket.resolved && matches!(ticket.status, Status::Resolved) {
                ticket.status = Status::Closed;
            }
        }
        Event::Reopen => {
            if matches!(ticket.status, Status::Resolved | Status::Closed) {
                ticket.resolved = false;
                ticket.blocked = false;
                ticket.status = Status::InProgress;
            }
        }
    }
}

