enum Shipment {
    Standard(u32),
    Express(u32),
    Priority { weight: u32, insured: bool },
    Unknown,
}

fn score(shipment: &Shipment) -> u32 {
    match shipment {
        Shipment::Standard(weight) => *weight,
        Shipment::Express(weight) => *weight,
        Shipment::Priority { weight, insured } => {
            if *insured {
                *weight + 1
            } else {
                *weight
            }
        }
        Shipment::Unknown => 1,
    }
}

fn bucket(shipment: &Shipment) -> &'static str {
    match shipment {
        Shipment::Standard(_) => "standard",
        Shipment::Express(weight) if *weight > 3 => "priority",
        Shipment::Express(_) => "express",
        Shipment::Priority { insured: false, .. } => "express",
        Shipment::Priority { .. } => "priority",
        Shipment::Unknown => "unknown",
    }
}

fn main() {
    let shipments = [
        Shipment::Standard(2),
        Shipment::Express(3),
        Shipment::Priority {
            weight: 4,
            insured: true,
        },
        Shipment::Priority {
            weight: 2,
            insured: false,
        },
        Shipment::Unknown,
    ];

    let mut standard = 0;
    let mut express = 0;
    let mut priority = 0;
    let mut unknown = 0;

    for shipment in &shipments {
        let pts = score(shipment);
        match bucket(shipment) {
            "standard" => standard += pts,
            "express" => express += pts,
            "priority" => priority += pts,
            _ => unknown += pts,
        }
    }

    println!("standard: {}", standard);
    println!("express: {}", express);
    println!("priority: {}", priority);
    println!("unknown: {}", unknown);
}

