#[derive(Clone, Copy)]
struct Booking {
    start: u32,
    end: u32,
}

impl Booking {
    fn fmt(&self) -> String {
        format!("[{}-{}]", hhmm(self.start), hhmm(self.end))
    }
}

fn hhmm(mins: u32) -> String {
    format!("{:02}:{:02}", mins / 60, mins % 60)
}

fn overlaps(a: Booking, b: Booking) -> bool {
    !(a.end < b.start || b.end < a.start)
}

fn try_book(existing: &mut Vec<Booking>, req: Booking) -> bool {
    if req.start > req.end {
        return false;
    }
    if existing.iter().any(|&b| overlaps(b, req)) {
        return false;
    }
    existing.push(req);
    true
}

fn main() {
    let requests = [
        Booking { start: 9 * 60, end: 10 * 60 },
        Booking { start: 10 * 60, end: 11 * 60 + 30 },
        Booking { start: 9 * 60 + 30, end: 9 * 60 + 45 },
        Booking { start: 11 * 60 + 30, end: 11 * 60 + 30 },
        Booking { start: 8 * 60 + 30, end: 9 * 60 },
        Booking { start: 11 * 60 + 30, end: 12 * 60 },
        Booking { start: 12 * 60, end: 13 * 60 },
        Booking { start: 10 * 60 + 45, end: 12 * 60 + 15 },
    ];

    let mut accepted = Vec::new();
    let mut out = Vec::new();

    for (i, req) in requests.into_iter().enumerate() {
        let ok = try_book(&mut accepted, req);
        let line = if ok {
            format!("accepted #{} {}", i + 1, req.fmt())
        } else {
            let reason = if req.start > req.end { "invalid" } else { "conflict" };
            format!("rejected #{} {} {}", i + 1, req.fmt(), reason)
        };
        out.push(line);
    }

    out.push("final schedule:".to_string());
    for b in &accepted {
        out.push(b.fmt());
    }

    print!("{}", out.join("\n"));
}

