use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
enum State {
    Open,
    InProgress,
    Closed,
}

#[derive(Clone, Copy, Debug)]
enum Event {
    Create,
    Start,
    Resolve,
    Reopen,
    Cancel,
}

#[derive(Clone, Copy, Debug)]
struct Ticket {
    state: State,
    history_len: usize,
}

fn main() {
    let events = vec![
        ("T1", Event::Start),
        ("T1", Event::Create),
        ("T1", Event::Start),
        ("T1", Event::Resolve),
        ("T1", Event::Reopen),
        ("T1", Event::Resolve),
        ("T2", Event::Create),
        ("T2", Event::Resolve),
        ("T2", Event::Start),
        ("T2", Event::Cancel),
        ("T3", Event::Create),
        ("T3", Event::Start),
        ("T3", Event::Resolve),
        ("T3", Event::Reopen),
        ("T3", Event::Cancel),
    ];

    let (tickets, invalid) = apply_events(&events);

    for (id, ticket) in tickets.iter() {
        println!("{} {:?} {}", id, ticket.state, ticket.history_len);
    }

    let mut open = 0;
    let mut in_progress = 0;
    let mut closed = 0;
    for ticket in tickets.values() {
        match ticket.state {
            State::Open => open += 1,
            State::InProgress => in_progress += 1,
            State::Closed => closed += 1,
        }
    }
    println!(
        "open={} in_progress={} closed={} invalid={}",
        open, in_progress, closed, invalid
    );
}

fn apply_events(events: &[(&str, Event)]) -> (BTreeMap<String, Ticket>, usize) {
    let mut tickets = BTreeMap::new();
    let mut invalid = 0;

    for (id, event) in events {
        let entry = tickets.entry((*id).to_string()).or_insert(Ticket {
            state: State::Open,
            history_len: 0,
        });

        let valid = match event {
            Event::Create => {
                if entry.history_len == 0 {
                    entry.state = State::Open;
                    true
                } else {
                    false
                }
            }
            Event::Start => {
                if matches!(entry.state, State::Open | State::Closed) {
                    entry.state = State::InProgress;
                    true
                } else {
                    false
                }
            }
            Event::Resolve => {
                if entry.state == State::InProgress {
                    entry.state = State::Closed;
                    true
                } else {
                    false
                }
            }
            Event::Reopen => {
                if entry.state == State::Closed {
                    entry.state = State::Open;
                    true
                } else {
                    false
                }
            }
            Event::Cancel => {
                entry.state = State::Closed;
                true
            }
        };

        if valid {
            entry.history_len += 1;
        } else {
            invalid += 1;
        }
    }

    (tickets, invalid)
}

