use std::collections::BTreeMap;

#[derive(Clone, Debug)]
struct Ticket {
    status: &'static str,
    owner: Option<&'static str>,
    hold_count: u32,
}

fn apply(ticket: &mut Ticket, event: &str) {
    match event {
        "create" => {
            ticket.status = "Open";
        }
        e if e.starts_with("assign:") => {
            ticket.owner = Some(&e[7..]);
            if ticket.status == "New" {
                ticket.status = "Open";
            }
        }
        "start" => {
            if ticket.status != "Canceled" {
                ticket.status = "InProgress";
            }
        }
        "pause" => {
            ticket.hold_count += 1;
            ticket.status = "OnHold";
        }
        "resume" => {
            if ticket.status == "OnHold" {
                ticket.hold_count += 1;
                ticket.status = "InProgress";
            }
        }
        "complete" => {
            ticket.status = "Done";
        }
        "cancel" => {
            ticket.status = "Canceled";
        }
        "reopen" => {
            ticket.status = "Open";
        }
        "unassign" => {
            if ticket.status != "Done" {
                ticket.owner = None;
            }
        }
        _ => {}
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "assign:alice"),
        ("A", "start"),
        ("A", "pause"),
        ("A", "resume"),
        ("A", "complete"),
