        ("B", "assign:bob"),
        ("B", "start"),
        ("B", "cancel"),
        ("B", "reopen"),
        ("B", "unassign"),
        ("B", "cancel"),
        ("C", "create"),
        ("C", "assign:carol"),
        ("C", "start"),
        ("C", "assign:dana"),
        ("C", "pause"),
        ("C", "resume"),
        ("C", "complete"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();

    for (id, event) in events {
        let ticket = tickets.entry(id).or_insert(Ticket {
            status: "New",
            owner: None,
            hold_count: 0,
        });
        apply(ticket, event);
    }

    let mut out = Vec::new();
    for (id, t) in tickets {
        out.push(format!(
            "{}:{} owner={} hold={}",
            id,
            t.status,
            t.owner.unwrap_or("-"),
            t.hold_count
        ));
    }
    println!("{}", out.join("\n"));
}

