#[derive(Clone, Copy)]
struct Booking {
    label: &'static str,
    start: i32,
    end: i32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    !(a.end < b.start || b.end < a.start)
}

fn can_accept(existing: &[Booking], new_booking: Booking, capacity: usize) -> bool {
    let mut concurrent = 0usize;
    for b in existing {
        if overlaps(b, &new_booking) {
            concurrent += 1;
        }
    }
    concurrent < capacity
}

fn active_segments(bookings: &[Booking]) -> Vec<(i32, i32, usize)> {
    let mut points = Vec::new();
    for b in bookings {
        points.push((b.start, 1i32));
        points.push((b.end, -1i32));
    }
    points.sort_by_key(|p| p.0);

    let mut out = Vec::new();
    let mut current = 0i32;
    for i in 0..points.len().saturating_sub(1) {
        current += points[i].1;
        let a = points[i].0;
        let b = points[i + 1].0;
        if a != b && current > 0 {
            out.push((a, b, current as usize));
        }
    }
    out
}

fn main() {
    let capacity = 2usize;
    let requests = [
        Booking { label: "A", start: 0, end: 10 },
        Booking { label: "B", start: 5, end: 15 },
        Booking { label: "C", start: 10, end: 20 },
        Booking { label: "D", start: 7, end: 12 },
        Booking { label: "E", start: 12, end: 20 },
        Booking { label: "F", start: 20, end: 20 },
        Booking { label: "G", start: 19, end: 18 },
    ];

    let mut accepted = Vec::new();
    let mut lines = Vec::new();
    lines.push("accepted:".to_string());
    for r in requests {
        let ok = can_accept(&accepted, r, capacity);
        lines.push(format!("{} {}", r.label, ok));
        if ok {
            accepted.push(r);
        }
    }

    lines.push("active_segments:".to_string());
    for (s, e, n) in active_segments(&accepted) {
        lines.push(format!("{}-{} x{}", s, e, n));
    }

    println!("{}", lines.join("\n"));
}

