    room: &'static str,
    start: u32,
    end: u32,
    seats: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_accept(existing: &[Booking], candidate: Booking, room_capacity: u32) -> bool {
    let mut used = 0;
    for b in existing {
        if b.room == candidate.room && overlaps(*b, candidate) {
            used += b.seats;
        }
    }
    used + candidate.seats < room_capacity
}

fn accepted_ids(bookings: &[Booking], room_capacity: u32) -> Vec<&'static str> {
    let mut accepted = Vec::new();
    let mut scheduled = Vec::new();

    for &b in bookings {
        if can_accept(&scheduled, b, room_capacity) {
            scheduled.push(b);
            accepted.push(b.id);
        }
    }

    accepted
}

