enum Action {
    Backup { remote: bool },
    Cleanup { dry_run: bool, force: bool },
    Deploy { approved: bool, emergency: bool },
    Report { daily: bool },
}

fn plan(action: &Action) -> String {
    match action {
        Action::Backup { remote } => {
            if *remote {
                "backup: upload backup".to_string()
            } else {
                "backup: queue backup".to_string()
            }
        }
        Action::Cleanup { dry_run, force } => {
            if *dry_run || *force {
                "cleanup: delete now".to_string()
            } else {
                "cleanup: skip".to_string()
            }
        }
        Action::Deploy { approved, emergency } => {
            if *approved && *emergency {
                "deploy: deploy immediately".to_string()
            } else {
                "deploy: wait for approval".to_string()
