use std::collections::HashSet;

fn validate(input: &str) -> String {
    let mut seen = HashSet::new();
    let mut valid = 0usize;
    let mut invalid = 0usize;
    let mut errors = Vec::new();

    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            invalid += 1;
            errors.push(format!("line {}: malformed", line_no));
            continue;
        }

        let id = parts[0].trim();
        let qty_str = parts[1].trim();
        let status = parts[2].trim();

        if id.is_empty() || !id.chars().all(|c| c.is_ascii_alphanumeric()) {
            invalid += 1;
            errors.push(format!("line {}: bad id {}", line_no, id));
            continue;
        }
        if seen.contains(id) {
            invalid += 1;
            errors.push(format!("line {}: duplicate id {}", line_no, id));
            continue;
        }
        seen.insert(id.to_string());

        let qty: u32 = match qty_str.parse() {
            Ok(n) => n,
            Err(_) => {
                invalid += 1;
                errors.push(format!("line {}: bad qty {}", line_no, qty_str));
                continue;
            }
        };
        if qty < 0 {
            invalid += 1;
            errors.push(format!("line {}: bad qty {}", line_no, qty_str));
            continue;
        }
        if status != "ok" && status != "hold" {
            invalid += 1;
            errors.push(format!("line {}: bad status {}", line_no, status));
            continue;
        }
        valid += 1;
    }

    let mut out = format!("valid: {}\ninvalid: {}", valid, invalid);
    if !errors.is_empty() {
        out.push_str("\nerrors:");
        for e in errors {
            out.push('\n');
            out.push_str(&e);
        }
    }
    out
}

fn main() {
    let input = "a1|3|ok
# comment
a2|2|hold
a1|1|ok
b7|0|ok
oops";
    println!("{}", validate(input));
}

