    let mut lines = Vec::new();

    for raw in input.lines() {
        match parse_line(raw) {
            Some((name, age, active)) if is_valid(name, age, active) => {
                ok += 1;
                lines.push(format!("{}:ok", name));
            }
            Some((name, _, _)) => {
                invalid += 1;
                lines.push(format!("{}:invalid", name));
            }
            None => {
                invalid += 1;
                lines.push("?:invalid".to_string());
            }
        }
    }

    println!("ok:{} invalid:{}", ok, invalid);
    for line in lines {
        println!("{}", line);
    }
}

