#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Cancelled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Reopen,
    Cancel,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::Open, Event::Cancel) => Status::Cancelled,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::InProgress, Event::Cancel) => Status::Cancelled,
        (Status::Resolved, Event::Reopen) => Status::Open,
        (Status::Cancelled, Event::Reopen) => Status::Open,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn normal_flow_reaches_resolved() {
        let events = [Event::Start, Event::Resolve];
        assert_eq!(apply_events(Status::Open, &events), Status::Resolved);
    }

    #[test]
    fn resolved_can_reopen_and_start_again() {
        let events = [Event::Start, Event::Resolve, Event::Reopen, Event::Start];
        assert_eq!(apply_events(Status::Open, &events), Status::InProgress);
    }

    #[test]
    fn cancelled_stays_cancelled() {
        let events = [Event::Cancel, Event::Reopen, Event::Start];
        assert_eq!(apply_events(Status::Open, &events), Status::Cancelled);
    }
}

