pub fn build_report(orders: &[Order]) -> Vec<String> {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for order in orders {
        *totals.entry(order.team).or_insert(0) += order.amount;
        *counts.entry(order.team).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    for (team, total) in totals {
        let count = counts.get(team).copied().unwrap_or(0);
        lines.push(format!("{}: total={}, orders={}", team, total, count));
