pub fn can_book(existing: &[(u32, u32)], new_slot: (u32, u32)) -> bool {
    let (start, end) = new_slot;
    if start >= end {
        return false;
    }

    for &(a, b) in existing {
        if start <= b && a <= end {
            return false;
        }
    }
    true
}

