pub fn summarize_sales(records: &[SaleRecord]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for r in records {
        let amount = if r.refunded { -r.amount } else { r.amount };
        *totals.entry(r.month).or_insert(0) += amount;
        *counts.entry(r.month).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    for (month, total) in totals {
        let count = counts.get(month).copied().unwrap_or(0);
        lines.push(format!("{}: total={}, sales={}", month, total, count));
    }
    lines.join("\n")
}

