pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u32>,
}

pub fn merge_config(
    defaults: &Config,
    env: Option<&PartialConfig>,
    user: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(layer) = user {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(use_tls) = layer.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = layer.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    if let Some(layer) = env {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(use_tls) = layer.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = layer.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    merged
}

