#[derive(Debug, PartialEq, Eq)]
pub struct Entry {
    pub id: u32,
    pub kind: String,
    pub active: bool,
}

pub fn parse_entries(input: &str) -> Result<Vec<Entry>, String> {
    let mut out = Vec::new();

    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut kind = None;
        let mut active = false;

        for field in line.split(';') {
            let mut parts = field.splitn(2, '=');
            let key = parts.next().ok_or_else(|| format!("line {}: bad field", line_no + 1))?.trim();
            let value = parts.next().ok_or_else(|| format!("line {}: bad field", line_no + 1))?.trim();

            match key {
                "id" => {
                    id = Some(value.parse::<u32>().map_err(|_| format!("line {}: invalid id", line_no + 1))?);
                }
                "kind" => {
                    if value.is_empty() {
                        return Err(format!("line {}: empty kind", line_no + 1));
                    }
                    kind = Some(value.to_string());
                }
                "active" => {
                    active = value == "true";
                }
                _ => {}
            }
        }

        out.push(Entry {
            id: id.ok_or_else(|| format!("line {}: missing id", line_no + 1))?,
            kind: kind.ok_or_else(|| format!("line {}: missing kind", line_no + 1))?,
            active,
        });
    }

    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_lines() {
        let input = "id=1;kind=alpha;active=true\nid=2;kind=beta;active=false";
        let got = parse_entries(input).unwrap();
        assert_eq!(
            got,
            vec![
                Entry { id: 1, kind: "alpha".into(), active: true },
                Entry { id: 2, kind: "beta".into(), active: false },
            ]
        );
    }

    #[test]
    fn rejects_unknown_key() {
        let err = parse_entries("id=1;kind=alpha;extra=nope;active=true").unwrap_err();
        assert_eq!(err, "line 1: unknown key extra");
    }

    #[test]
    fn rejects_invalid_active_value() {
        let err = parse_entries("id=1;kind=alpha;active=yes").unwrap_err();
        assert_eq!(err, "line 1: invalid active");
    }

    #[test]
    fn rejects_missing_active_field() {
        let err = parse_entries("id=1;kind=alpha").unwrap_err();
        assert_eq!(err, "line 1: missing active");
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        (Status::Closed, Event::Reopen) => Status::Open,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn normal_flow_reaches_closed() {
        let mut s = Status::Open;
        s = apply_event(s, Event::Start);
        s = apply_event(s, Event::Resolve);
        s = apply_event(s, Event::Close);
        assert_eq!(s, Status::Closed);
    }

    #[test]
    fn reopen_from_resolved_goes_back_to_in_progress() {
        let s = apply_event(Status::Resolved, Event::Reopen);
        assert_eq!(s, Status::InProgress);
    }

    #[test]
    fn reopen_from_closed_goes_back_to_open() {
        let s = apply_event(Status::Closed, Event::Reopen);
        assert_eq!(s, Status::Open);
    }

    #[test]
    fn closing_from_in_progress_is_ignored() {
        let s = apply_event(Status::InProgress, Event::Close);
        assert_eq!(s, Status::InProgress);
    }
}

