#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::InProgress,
        _ => status,
    }
}

pub fn replay(events: &[Event]) -> Status {
    let mut status = Status::Open;
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
