            Status::Open
        );
    }

    #[test]
    fn reopened_ticket_can_start_again() {
        assert_eq!(
            replay(&[Event::Start, Event::Resolve, Event::Reopen, Event::Start]),
            Status::InProgress
        );
    }
}

