        let state = apply_event(OrderState::Submitted, Event::Ship);
        assert_eq!(state, OrderState::Submitted);
    }

    #[test]
    fn cannot_cancel_after_payment() {
        let state = apply_event(OrderState::Paid, Event::Cancel);
        assert_eq!(state, OrderState::Paid);
    }
