pub struct Config {
    pub host: String,
    pub port: u16,
    pub debug: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub debug: Option<bool>,
}

pub fn merge_config(
    defaults: &Config,
    env: &PartialConfig,
    explicit: &PartialConfig,
) -> Config {
    Config {
        host: env
            .host
            .clone()
            .or_else(|| explicit.host.clone())
            .unwrap_or_else(|| defaults.host.clone()),
        port: explicit.port.or(env.port).unwrap_or(defaults.port),
        debug: explicit.debug.unwrap_or(env.debug.unwrap_or(defaults.debug)),
    }
}

