use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: u32,
    pub refunded: bool,
}

pub fn summarize_by_region(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for order in orders {
        let entry = totals.entry(order.region).or_insert((0, 0));
        entry.0 += order.amount_cents;
        entry.1 += 1;
    }

    let mut lines = Vec::new();
    for (region, (total, count)) in totals {
        lines.push(format!("{}: ${:.2} ({} orders)", region, total as f64 / 100.0, count));
    }

    if lines.is_empty() {
        "no sales".to_string()
    } else {
        lines.join("\n")
    }
}

