    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Archive,
}

pub fn next_state(current: State, event: Event) -> State {
    match (current, event) {
        (State::Draft, Event::Submit) => State::Review,
        (State::Review, Event::Approve) => State::Published,
        (State::Review, Event::Reject) => State::Draft,
        (State::Published, Event::Archive) => State::Archived,
        (State::Archived, Event::Reject) => State::Draft,
        _ => current,
    }
}

