#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Review,
    Published,
    Archived,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Archive,
    Restore,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Item {
    status: Status,
    approved_once: bool,
}

impl Item {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            approved_once: false,
        }
    }

    pub fn status(&self) -> Status {
        self.status
    }

    pub fn approved_once(&self) -> bool {
        self.approved_once
    }

    pub fn apply(&mut self, event: Event) {
        match (self.status, event) {
            (Status::Draft, Event::Submit) => self.status = Status::Review,
            (Status::Review, Event::Approve) => {
                self.status = Status::Published;
            }
            (Status::Review, Event::Reject) => self.status = Status::Draft,
            (_, Event::Archive) => self.status = Status::Archived,
            (Status::Archived, Event::Restore) => self.status = Status::Draft,
            _ => {}
        }
    }
}

pub fn replay(events: &[Event]) -> Item {
    let mut item = Item::new();
    for event in events.iter().cloned() {
        item.apply(event);
    }
    item
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn approval_marks_history_and_restore_depends_on_it() {
        let mut item = Item::new();
        item.apply(Event::Submit);
        item.apply(Event::Approve);
        assert_eq!(item.status(), Status::Published);
        assert!(item.approved_once());

        item.apply(Event::Archive);
        item.apply(Event::Restore);
        assert_eq!(item.status(), Status::Review);
    }

    #[test]
    fn restore_without_prior_approval_goes_to_draft() {
        let item = replay(&[Event::Submit, Event::Reject, Event::Archive, Event::Restore]);
        assert_eq!(item.status(), Status::Draft);
        assert!(!item.approved_once());
    }

    #[test]
    fn archive_only_allowed_from_published_or_review() {
        let mut item = Item::new();
        item.apply(Event::Archive);
        assert_eq!(item.status(), Status::Draft);

        item.apply(Event::Submit);
        item.apply(Event::Archive);
        assert_eq!(item.status(), Status::Archived);
    }

    #[test]
    fn replay_preserves_approval_memory_across_later_rejections() {
        let item = replay(&[
            Event::Submit,
            Event::Approve,
            Event::Archive,
            Event::Restore,
            Event::Reject,
            Event::Archive,
            Event::Restore,
        ]);
        assert_eq!(item.status(), Status::Review);
        assert!(item.approved_once());
    }
}

