pub fn select_codes(input: &str, min_score: i32) -> String {
    let mut picked: Vec<(String, i32)> = input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let code = parts.next()?.trim();
            let score = parts.next()?.trim().parse::<i32>().ok()?;
            let active = parts.next()?.trim();

            if code.is_empty() || active != "on" || score <= min_score {
                return None;
            }

            Some((code.to_string(), score))
        })
        .collect();

    picked.sort_by(|a, b| a.1.cmp(&b.1));

    picked
        .into_iter()
        .map(|(code, _)| code)
        .collect::<Vec<_>>()
        .join(",")
}

