    }) {
        if let Some((_, existing_score)) = picked.iter_mut().find(|(existing_code, _)| existing_code == &code) {
            if score > *existing_score {
                *existing_score = score;
            }
        } else {
            picked.push((code, score));
        }
    }

    picked.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));

    picked
        .into_iter()
        .map(|(code, _)| code)
        .collect::<Vec<_>>()
        .join(",")
}

