pub struct Player {
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut items = players.to_vec();
    items.sort_by_key(|p| (Reverse(p.score), p.name, Reverse(p.wins)));

    items
        .into_iter()
        .enumerate()
        .map(|(idx, p)| format!("{}. {} ({} pts, {} wins)", idx + 1, p.name, p.score, p.wins))
        .collect()
}

