pub fn extract_codes(input: &str) -> Vec<String> {
    input
        .split(',')
        .filter_map(|part| {
            let token = part.trim();
            let prefix: String = token.chars().take_while(|c| c.is_ascii_uppercase()).collect();
            let digits: String = token.chars().skip_while(|c| c.is_ascii_uppercase()).take_while(|c| c.is_ascii_digit()).collect();

            if !prefix.is_empty() && !digits.is_empty() {
                Some(format!("{}-{}", prefix, digits))
            } else {
                None
            }
        })
        .collect()
}

