#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub points: u32,
    pub goal_diff: i32,
}

fn points(p: &Player) -> u32 {
    p.wins * 3 + p.draws
}

fn goal_diff(p: &Player) -> i32 {
    p.wins as i32 - p.losses as i32
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items: Vec<_> = players
        .iter()
        .map(|p| RankedPlayer {
            rank: 0,
            name: p.name,
            points: points(p),
            goal_diff: goal_diff(p),
        })
        .collect();

    items.sort_by(|a, b| {
        b.points
            .cmp(&a.points)
            .then_with(|| a.name.cmp(b.name))
    });

    for (i, item) in items.iter_mut().enumerate() {
        item.rank = i + 1;
    }

    items
}

