            Player { name: "Hawks", wins: 3, draws: 3, losses: 0 },
            Player { name: "Owls", wins: 4, draws: 0, losses: 2 },
        ];

        let ranked = rank_players(&players);
        let names: Vec<_> = ranked.iter().map(|r| r.name).collect();
        assert_eq!(names, vec!["Hawks", "Bears", "Lions", "Owls"]);
