#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
}

pub fn next_status(current: Status, event: Event) -> Status {
    match (current, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::Open,
        (s, _) => s,
    }
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    events.iter().copied().fold(initial, next_status)
}

#[cfg(test)]
mod tests {
    use super::{apply_events, next_status, Event, Status};

    #[test]
    fn basic_flow_reaches_closed() {
        let events = [Event::Start, Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }

    #[test]
    fn blocked_item_can_be_unblocked_and_resolved() {
        let events = [Event::Start, Event::Block, Event::Unblock, Event::Resolve];
        assert_eq!(apply_events(Status::Open, &events), Status::Resolved);
    }

    #[test]
    fn reopen_from_resolved_goes_to_open() {
        assert_eq!(next_status(Status::Resolved, Event::Reopen), Status::Open);
    }

    #[test]
    fn closing_directly_from_resolved_or_blocked_is_not_allowed() {
        assert_eq!(next_status(Status::Resolved, Event::Close), Status::Resolved);
        assert_eq!(next_status(Status::Blocked, Event::Close), Status::Blocked);
    }

    #[test]
    fn closed_is_terminal_for_non_reopen_events() {
        let events = [Event::Start, Event::Resolve, Event::Close, Event::Start, Event::Block];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }
}

