    pub user: &'a str,
    pub amount: i32,
    pub ok: bool,
}

pub fn collect_alerts(events: &[Event<'_>], min_amount: i32) -> Vec<String> {
    let mut out: Vec<String> = events
        .iter()
        .filter(|e| e.ok)
        .filter(|e| e.amount >= min_amount)
        .filter_map(|e| match e.kind {
            "purchase" => Some(format!("{}:{}", e.user, e.amount)),
            "refund" => Some(format!("{}:-{}", e.user, e.amount)),
            _ => None,
        })
        .collect();

    out.sort();
    out.dedup();
    out
}

