#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    Active,
    Paused,
    Completed,
    Canceled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Pause,
    Resume,
    Complete,
    Cancel,
}

pub fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::Draft, Event::Submit) => State::Active,
        (State::Draft, Event::Cancel) => State::Canceled,
        (State::Active, Event::Pause) => State::Paused,
        (State::Active, Event::Complete) => State::Completed,
        (State::Active, Event::Cancel) => State::Canceled,
        (State::Paused, Event::Resume) => State::Active,
        (State::Paused, Event::Complete) => State::Completed,
        (_, Event::Cancel) => State::Canceled,
        _ => state,
    }
}

pub fn apply_events(mut state: State, events: &[Event]) -> State {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
mod tests {
    use super::{apply_event, apply_events, Event::*, State::*};

    #[test]
    fn paused_can_resume_and_complete() {
        assert_eq!(apply_events(Draft, &[Submit, Pause, Resume, Complete]), Completed);
    }

    #[test]
    fn completed_is_terminal() {
        assert_eq!(apply_event(Completed, Cancel), Completed);
        assert_eq!(apply_events(Completed, &[Resume, Cancel, Pause]), Completed);
    }

    #[test]
    fn canceled_is_terminal() {
        assert_eq!(apply_event(Canceled, Resume), Canceled);
        assert_eq!(apply_events(Draft, &[Cancel, Submit, Complete]), Canceled);
    }

    #[test]
    fn invalid_events_leave_state_unchanged() {
        assert_eq!(apply_event(Draft, Resume), Draft);
        assert_eq!(apply_event(Paused, Submit), Paused);
    }
}

