pub fn can_book(existing: &[(u32, u32)], requested: (u32, u32)) -> bool {
    let (start, end) = requested;
    if start > end {
        return false;
    }

    for &(a, b) in existing {
        if start <= b && a <= end {
            return false;
        }
    }
    true
}

#[cfg(test)]
