    #[test]
    fn rejects_clear_overlap() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(!can_book(&existing, (15, 18)));
        assert!(!can_book(&existing, (18, 35)));
    }

    #[test]
    fn allows_adjacent_non_overlapping_ranges() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(can_book(&existing, (20, 30)));
        assert!(can_book(&existing, (0, 10)));
        assert!(can_book(&existing, (40, 50)));
    }

    #[test]
    fn rejects_zero_length_and_reversed_requests() {
        let existing = vec![(5, 8)];
        assert!(!can_book(&existing, (7, 7)));
        assert!(!can_book(&existing, (9, 8)));
    }

    #[test]
    fn empty_schedule_accepts_valid_request() {
        let existing: Vec<(u32, u32)> = vec![];
        assert!(can_book(&existing, (1, 2)));
    }
}

