use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: &'static str,
    pub member: &'static str,
    pub score: i32,
    pub active: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TeamStats {
    total: i32,
    contributors: usize,
}

pub fn build_report(entries: &[Entry]) -> String {
    let mut stats: BTreeMap<&str, TeamStats> = BTreeMap::new();

    for e in entries {
        let team = stats.entry(e.team).or_insert(TeamStats {
            total: 0,
            contributors: 0,
        });
        if e.active && e.score > 0 {
            team.total += e.score;
            team.contributors += 1;
        }
    }

    let mut rows: Vec<_> = stats.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(name, s)| format!("{}:{}:{}", name, s.total, s.contributors))
        .collect::<Vec<_>>()
        .join("\n")
}

