pub fn collect_visible_tags(lines: &[&str]) -> Vec<String> {
    lines
        .iter()
        .filter_map(|line| {
            let (name, rest) = line.split_once(':')?;
            if name.is_empty() {
                return None;
            }

            let mut tags = rest.split('|');
            let first = tags.next()?.trim();
            if first.is_empty() || first.starts_with('!') {
                return None;
            }

            Some(format!("{}#{}", name.trim(), first.to_ascii_lowercase()))
        })
        .collect()
}

