        let mut seen = std::collections::BTreeSet::new();
        let tags: Vec<String> = rest
            .split('|')
            .map(str::trim)
            .filter(|tag| !tag.is_empty() && !tag.starts_with('!'))
            .map(|tag| tag.to_ascii_lowercase())
            .filter(|tag| seen.insert(tag.clone()))
            .collect();

        if tags.is_empty() {
            None
        } else {
            Some(tags.into_iter().map(|tag| format!("{}#{}", name, tag)).collect::<Vec<_>>())
        }
    })
    .flatten()
    .collect();
out.sort();
out.dedup();
out

