#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub timeout_ms: u64,
    pub retries: u8,
    pub tags: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub timeout_ms: Option<u64>,
    pub retries: Option<u8>,
    pub tags: Option<Vec<String>>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut out = defaults.clone();

    for layer in [file, env, cli] {
        if let Some(layer) = layer {
            if let Some(host) = &layer.host {
                out.host = host.clone();
            }
            if let Some(port) = layer.port {
                out.port = port;
            }
            if let Some(tls) = layer.tls {
                out.tls = tls;
            }
            if let Some(timeout_ms) = layer.timeout_ms {
                out.timeout_ms = timeout_ms;
            }
            if let Some(retries) = layer.retries {
                out.retries = retries;
            }
            if let Some(tags) = &layer.tags {
                out.tags.extend(tags.clone());
            }
        }
    }

    out
}

