            retries: 3,
            tags: vec!["base".into()],
        }
    }

    #[test]
    fn precedence_is_defaults_then_file_then_env_then_cli() {
        let file = PartialConfig {
            host: Some("file.internal".into()),
            port: Some(9000),
            tls: Some(true),
            timeout_ms: Some(2_000),
            retries: Some(4),
            tags: Some(vec!["file".into()]),
        };
        let env = PartialConfig {
            host: Some("env.internal".into()),
            port: Some(7000),
            tls: None,
            timeout_ms: Some(3_000),
            retries: None,
            tags: Some(vec!["env".into()]),
        };
        let cli = PartialConfig {
            host: None,
            port: Some(6000),
            tls: Some(false),
            timeout_ms: None,
            retries: Some(8),
            tags: Some(vec!["cli".into()]),
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env), Some(&cli));

        assert_eq!(merged.host, "env.internal");
        assert_eq!(merged.port, 6000);
        assert!(!merged.tls);
        assert_eq!(merged.timeout_ms, 3_000);
        assert_eq!(merged.retries, 8);
        assert_eq!(merged.tags, vec!["cli"]);
    }

