use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Closed,
    Reopened,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
            Status::Reopened => "Reopened",
        }
    }
}

enum Event {
    Start,
    Resolve,
    Reopen,
}

fn apply_event(status: Status, event: Event) -> Status {
    match event {
        Event::Start => Status::InProgress,
        Event::Resolve => Status::Closed,
        Event::Reopen => Status::Open,
    }
}

fn main() {
    let events = [
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("B", Event::Resolve),
        ("B", Event::Reopen),
        ("C", Event::Start),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();

    for (id, event) in events {
        let current = tickets.get(id).copied().unwrap_or(Status::Open);
        let next = apply_event(current, event);
        tickets.insert(id, next);
    }

    for (id, status) in tickets {
        println!("{}: {}", id, status.as_str());
    }
}

steps.replace:
