enum Action {
    Ship { item: &'static str, qty: u32 },
    Move { from: &'static str, to: &'static str },
    Inspect { area: &'static str, notes: Vec<&'static str> },
    Hold { reason: &'static str },
}

fn render(action: &Action) -> String {
    match action {
        Action::Ship { item, qty } => format!("ship {item} x{qty}"),
        Action::Move { from, to } => format!("move {to}->{from}"),
        Action::Inspect { area, notes } => format!("inspect {area} : {} notes", notes.len() + 1),
        Action::Hold { reason } => format!("hold due to pending {reason}"),
    }
}

fn summary(actions: &[Action]) -> String {
    let mut shipped = 0;
    let mut moved = 0;
    let mut inspected = 0;
    let mut held = 0;

    for action in actions {
        match action {
            Action::Ship { .. } => shipped += 1,
            Action::Move { .. } => moved += 1,
            Action::Inspect { .. } => inspected += 1,
            Action::Hold { .. } => moved += 1,
        }
    }

    format!(
        "summary shipped={shipped} moved={moved} inspected={inspected} held={held}"
    )
}

