            area: "seal",
            notes: vec!["photo", "temp", "signature"],
        },
        Action::Hold { reason: "weather" },
    ];

    let mut lines: Vec<String> = plan.iter().map(render).collect();
    lines.push(summary(&plan));
    print!("{}", lines.join("\n"));
}

