fn can_book(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    existing.iter().all(|&(s, e)| !overlaps(s, e, candidate.0, candidate.1))
}

fn main() {
    let requests = vec![(1, 10, 12), (2, 12, 14), (3, 9, 10), (4, 11, 13), (5, 14, 15)];
    let mut accepted: Vec<(u32, u32)> = Vec::new();
    let mut accepted_ids = Vec::new();
    let mut rejected_ids = Vec::new();

    for (id, start, end) in requests {
        if can_book(&accepted, (start, end)) {
            accepted.push((start, end));
            accepted_ids.push(id);
        } else {
            rejected_ids.push(id);
        }
    }

    println!("accepted: {:?}", rejected_ids);
    println!("rejected: {:?}", accepted_ids);
}

