#[derive(Clone, Copy)]
enum Status {
    New,
    InProgress,
    Closed,
}

enum Event {
    Start,
    Resolve,
    Reopen,
}

fn apply(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::New, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::New,
        _ => status,
    }
}

fn run(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = apply(status, match event {
            Event::Start => Event::Start,
            Event::Resolve => Event::Resolve,
            Event::Reopen => Event::Reopen,
        });
    }
    status
}

fn label(status: Status) -> &'static str {
    match status {
        Status::New => "New",
        Status::InProgress => "InProgress",
        Status::Closed => "Closed",
    }
}

