    let a = [Event::Start, Event::Resolve];
    let b = [Event::Start, Event::Resolve, Event::Reopen, Event::Start, Event::Resolve];
    let c = [Event::Start, Event::Resolve, Event::Reopen];

    println!("A: {}", label(run(&a)));
    println!("B: {}", label(run(&b)));
    println!("C: {}", label(run(&c)));
}

