enum Command<'a> {
    Set { key: &'a str, value: &'a str },
    Toggle { feature: &'a str, enabled: bool },
    Rename { from: &'a str, to: &'a str },
    Noop,
    Unknown(&'a str),
}

struct Totals {
    updates: usize,
    disabled: usize,
    renamed: usize,
    noop: usize,
    invalid: usize,
    unknown: usize,
}

fn classify(line: &str) -> (&str, Command<'_>) {
    let (target, body) = line.split_once(':').unwrap();
    let mut parts = body.split('|');
    match parts.next().unwrap() {
        "set" => {
            let key = parts.next().unwrap_or("");
            let value = parts.next().unwrap_or("");
            (target, Command::Set { key, value })
        }
        "toggle" => {
            let feature = parts.next().unwrap_or("");
            let enabled = matches!(parts.next().unwrap_or("false"), "on" | "true" | "enabled");
            (target, Command::Toggle { feature, enabled })
        }
        "rename" => {
            let from = parts.next().unwrap_or("");
            let to = parts.next().unwrap_or("");
            (target, Command::Rename { from, to })
        }
        "noop" => (target, Command::Noop),
        other => (target, Command::Unknown(other)),
    }
}

fn render(target: &str, cmd: Command<'_>, totals: &mut Totals) -> String {
    match cmd {
        Command::Set { key, value } => {
            totals.updates += 1;
            format!("{target} => set {key} = {value}")
        }
        Command::Toggle { feature, enabled } => {
            if enabled {
                totals.updates += 1;
                format!("{target} => enabled feature {feature}")
            } else {
                totals.updates += 1;
                format!("{target} => enabled feature {feature}")
            }
        }
        Command::Rename { from, to } => {
            totals.renamed += 1;
            format!("{target} => renamed {from} -> {to}")
        }
        Command::Noop => {
            totals.noop += 1;
            format!("{target} => noop")
        }
        Command::Unknown(name) => {
            totals.unknown += 1;
            format!("{target} => unknown {name}")
        }
    }
}

fn main() {
    let input = [
        "alpha:set|retries|3",
        "beta:noop",
        "gamma:toggle|cache|off",
        "legacy:rename|old_api|new_api",
        "delta:set|retries|x",
        "unknown:mystery|payload",
    ];

    let mut totals = Totals {
        updates: 0,
        disabled: 0,
        renamed: 0,
        noop: 0,
        invalid: 0,
        unknown: 0,
    };

    let mut lines = Vec::new();
    for line in input {
        let (target, cmd) = classify(line);
        lines.push(render(target, cmd, &mut totals));
    }

    lines.push(format!(
        "summary: updates={} disabled={} renamed={} noop={} invalid={} unknown={}",
        totals.updates, totals.disabled, totals.renamed, totals.noop, totals.invalid, totals.unknown
    ));

    print!("{}", lines.join("\n"));
}

