extra|1|1.00|ok|note
"#;

fn valid_price(s: &str) -> bool {
    s.parse::<f64>().is_ok()
}

fn main() {
    let mut out = Vec::new();

    for line in INPUT.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let parts: Vec<&str> = line.split('|').map(|p| p.trim()).collect();
        if parts.len() < 4 {
            continue;
        }

        let name = parts[0];
        let qty = parts[1];
        let price = parts[2];
        let status = parts[3];

        if name.is_empty() {
            continue;
        }
        if qty.parse::<i32>().is_err() {
            continue;
        }
        if !valid_price(price) {
            continue;
        }
        if status != "ok" && status != "hold" {
            continue;
        }

        out.push(format!("{}:{}:{}:{}", name, qty, price, status));
    }

    print!("{}", out.join("\n"));
