#[derive(Clone, Copy)]
enum State {
    New,
    InProgress,
    Closed,
}

enum Event {
    Start,
    Resolve,
    Reopen,
}

fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::New, Event::Start) => State::InProgress,
        (State::InProgress, Event::Resolve) => State::InProgress,
        (State::Closed, Event::Reopen) => State::InProgress,
        (s, _) => s,
    }
}

fn label(state: State) -> &'static str {
    match state {
        State::New => "New",
        State::InProgress => "InProgress",
        State::Closed => "Closed",
    }
}

fn run(events: &[Event]) -> State {
    let mut state = State::New;
    for event in events {
        state = apply_event(state, match event {
            Event::Start => Event::Start,
            Event::Resolve => Event::Resolve,
            Event::Reopen => Event::Reopen,
        });
    }
    state
}

fn main() {
    let t1 = run(&[Event::Start]);
    let t2 = run(&[Event::Start, Event::Resolve]);
    let t3 = run(&[Event::Reopen]);

    println!("T1:{}", label(t1));
    println!("T2:{}", label(t2));
    println!("T3:{}", label(t3));
}

