    Fragile,
    Signature,
    AgeCheck,
    DeskDrop,
}

struct Order {
    id: &'static str,
    service: Service,
    priority: bool,
    extra: Option<Extra>,
}

fn summarize(orders: &[Order]) -> String {
    let mut deliveries = 0;
    let mut charge_cents = 0;
    let mut priority = 0;
    let mut notes: Vec<&'static str> = Vec::new();

    for order in orders {
        match order.service {
            Service::Standard => {
                deliveries += 1;
                charge_cents += 400;
            }
            Service::Express => {
                deliveries += 1;
                charge_cents += 700;
            }
