                deliveries += 1;
                charge_cents += 250;
            }
        }

        if order.priority {
            priority += 1;
            charge_cents += 120;
        }

        if let Some(extra) = &order.extra {
            match extra {
                Extra::Fragile => {
                    charge_cents += 80;
                    notes.push("fragile");
                }
                Extra::Signature => {
                    charge_cents += 40;
                    notes.push("signature");
                }
                Extra::AgeCheck => {
