fn parse_record(line: &str) -> Option<(String, u32)> {
    let mut id = String::new();
    let mut qty = 0u32;

    for part in line.split(';') {
        let (key, value) = part.split_once('=')?;
        match key {
            "id" => id = value.to_string(),
            "qty" => qty = value.parse().ok()?,
            _ => return None,
        }
    }

    Some((id, qty))
}

