enum Route<'a> {
    Admin { signed_in: bool },
    Audit { can_view: bool },
    Profile { user: &'a str, canonical: bool },
    Download { ext: &'a str, inline: bool },
    Search { query: &'a str },
}

enum Action<'a> {
    Render(&'a str),
    Redirect(&'a str),
    Deny,
    Stream(&'a str),
    Rewrite(String),
}

fn resolve(route: &Route<'_>) -> Action<'_> {
    match route {
        Route::Admin { signed_in } => {
            if *signed_in { Action::Render("admin-dashboard") } else { Action::Redirect("/login") }
        }
        Route::Audit { can_view } => {
            if *can_view { Action::Render("audit-log") } else { Action::Redirect("/forbidden") }
        }
        Route::Profile { user, canonical } => {
            if *canonical { Action::Render("profile") } else { Action::Rewrite(format!("/users/{user}")) }
        }
        Route::Download { ext, inline } => {
            if *inline && *ext == "txt" { Action::Render("text-inline") } else { Action::Stream("application/octet-stream") }
        }
        Route::Search { query } => {
            if query.is_empty() { Action::Redirect("/browse") } else { Action::Render("search") }
        }
    }
}

fn summarize(name: &str, action: Action<'_>) -> String {
    match action {
        Action::Render(view) => format!("{name} => render:{view}"),
        Action::Redirect(to) => format!("{name} => redirect:{to}"),
        Action::Deny => format!("{name} => deny"),
        Action::Stream(kind) => format!("{name} => stream:{kind}"),
        Action::Rewrite(to) => format!("{name} => rewrite:{to}"),
    }
}

fn main() {
    let cases = [
        ("admin-dashboard", Route::Admin { signed_in: false }),
        ("audit-log", Route::Audit { can_view: false }),
        ("profile", Route::Profile { user: "alice", canonical: false }),
        ("download-report", Route::Download { ext: "csv", inline: true }),
        ("search", Route::Search { query: "rust enums" }),
    ];

    for (i, (name, route)) in cases.iter().enumerate() {
        if i > 0 {
            println!();
        }
        print!("{}", summarize(name, resolve(route)));
    }
}

