use std::collections::HashSet;

fn parse_line(line_no: usize, line: &str, seen: &mut HashSet<String>) -> Result<String, String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 4 {
        return Err(format!("line{}: wrong field count", line_no));
    }

    let id = parts[0];
    let name = parts[1];
    let age = parts[2].parse::<u32>().unwrap_or(0);
    let active = parts[3];

    if id.is_empty() || !id.chars().all(|c| c.is_ascii_lowercase()) {
        return Err(format!("line{}: bad id", line_no));
    }
    if !seen.insert(id.to_string()) {
        return Err(format!("line{}: duplicate id", line_no));
    }
    if age == 0 {
        return Err(format!("line{}: bad age", line_no));
    }
    if active != "true" && active != "false" {
        return Err(format!("line{}: bad active", line_no));
    }

    Ok(name.to_string())
}

fn main() {
    let input = "alpha|Ada|34|true\nbeta|Bob|xx|false\nalpha|Eve|22|true\ngamma|Gus|41|maybe\ndelta|Dot|19|true|extra\ngamma|Gia|28|false";

    let mut seen = HashSet::new();
    let mut ok = Vec::new();
    let mut err = Vec::new();

    for (i, line) in input.lines().enumerate() {
        match parse_line(i + 1, line, &mut seen) {
            Ok(name) => ok.push(format!("ok:{}", name.to_lowercase())),
            Err(e) => err.push(format!("err:{}", e)),
        }
    }

    println!("valid={} invalid={}", ok.len(), err.len());
    for line in ok {
        println!("{}", line);
    }
    for line in err {
        println!("{}", line);
    }
}

