fn apply_event(state: &str, event: &str) -> String {
    match (state, event) {
        ("new", "start") => "in_progress".to_string(),
        ("in_progress", "resolve") => "closed".to_string(),
        ("closed", "reopen") => "new".to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let tickets = [
        ("A", vec!["start", "resolve"]),
        ("B", vec!["start", "resolve", "reopen", "start"]),
        ("C", vec!["start", "resolve", "reopen", "resolve"]),
    ];

    let mut out = Vec::new();
    for (id, events) in tickets {
        let mut state = "new".to_string();
        for event in events {
            state = apply_event(&state, event);
        }
        out.push(format!("{}: {}", id, state));
    }

    println!("{}", out.join("\n"));
}

