fn plan(req: &Request) -> String {
    match (&req.service, &req.payload) {
        (Service::Standard, Payload::Bulk(n)) => format!("STD bulk {} -> desk", n),
        (Service::Standard, Payload::Fragile { .. }) => "STD standard-pack".to_string(),
        (Service::Express, Payload::Fragile { weight_kg }) => format!("EXP fragile {}kg -> fastlane", weight_kg),
        (Service::Express, Payload::Documents) => "EXP docs -> pouch".to_string(),
        (Service::International, Payload::Documents) => {
            if req.customs_ready {
                format!("INTL clear docs for {}", req.destination)
            } else {
                format!("INTL hold docs for {}", req.destination)
            }
        }
        (Service::International, Payload::Bulk(n)) => format!("INTL bulk {} -> pallet", n),
        (Service::International, Payload::Fragile { weight_kg }) => {
