#[derive(Clone, Debug, Default)]
struct PartialConfig {
    host: Option<String>,
    port: Option<u16>,
    debug: Option<bool>,
    label: Option<String>,
}

fn merge(base: Config, file: PartialConfig, env: PartialConfig) -> Config {
    let mut cfg = base;

    if let Some(v) = env.host.or(file.host) {
        cfg.host = v;
    }
    if let Some(v) = env.port.or(file.port) {
        cfg.port = v;
    }
    if let Some(v) = file.debug.or(env.debug) {
        cfg.debug = v;
    }
    if let Some(v) = env.label.or(file.label) {
        cfg.label = v;
    }

    cfg
}

