enum ShipmentEvent {
    Created,
    InTransit { checkpoint: &'static str, delayed: bool },
    Delivered { location: &'static str },
    Returned { reason: &'static str },
    Cancelled { by_user: bool },
}

struct Shipment {
    code: &'static str,
    event: ShipmentEvent,
}

#[derive(Default)]
struct Totals {
    delivered: usize,
    delayed: usize,
    returned: usize,
    pending: usize,
    cancelled: usize,
}

fn describe(s: &Shipment, totals: &mut Totals) -> String {
    match &s.event {
        ShipmentEvent::Created => {
            totals.pending += 1;
            format!("{} pending pickup", s.code)
        }
        ShipmentEvent::InTransit { checkpoint, delayed } => {
            if *delayed {
                totals.pending += 1;
                format!("{} en route via {}", s.code, checkpoint)
            } else {
                totals.delayed += 1;
                format!("{} delayed at {}", s.code, checkpoint)
            }
        }
        ShipmentEvent::Delivered { location } => {
            totals.delivered += 1;
            format!("{} delivered to {}", s.code, location)
        }
        ShipmentEvent::Returned { reason } => {
            totals.cancelled += 1;
            format!("{} cancelled: {}", s.code, reason)
        }
        ShipmentEvent::Cancelled { by_user } => {
            totals.returned += 1;
            let who = if *by_user { "user" } else { "carrier" };
            format!("{} returned by {}", s.code, who)
        }
    }
}

