fn apply_event(state: &str, event: &str) -> String {
    match (state, event) {
        ("New", "start") => "InProgress".to_string(),
        ("InProgress", "resolve") => "Closed".to_string(),
        ("Closed", "reopen") => "Closed".to_string(),
        _ => state.to_string(),
    }
}

