        ("T2", vec!["start", "resolve", "reopen"]),
        ("T3", vec!["resolve"]),
    ];

    let mut out = Vec::new();
    for (id, events) in tickets {
        let mut state = "New".to_string();
        for event in events {
            state = apply_event(&state, event);
        }
        out.push(format!("{}:{}", id, state));
    }

