}

enum Target {
    Cloud,
    Edge,
    Backup,
}

enum Action {
    Upload { files: usize, dry_run: bool },
    Download { name: &'static str },
    Mirror { path: &'static str, verify: bool },
    Delete { name: &'static str, force: bool },
}

struct Task {
    target: Target,
    action: Action,
}

fn render(task: &Task) -> String {
    match (&task.target, &task.action) {
        (Target::Cloud, Action::Upload { files, dry_run }) => {
            if *dry_run {
                format!("upload:done {} file(s) to cloud", files)
            } else {
                format!("upload:skip dry-run for {} file(s)", files)
            }
        }
        (Target::Edge, Action::Download { name }) => {
            format!("download:done {} from cloud", name)
        }
        (Target::Backup, Action::Mirror { path, verify }) => {
            let pass = if *verify { 1 } else { 2 };
            format!("mirror:done {} to backup ({} pass)", path, pass)
        }
        (_, Action::Delete { name, force }) => {
            if *force {
                format!("delete:denied {}", name)
            } else {
                format!("delete:done {}", name)
            }
        }
        (target, action) => {
            let t = match target {
                Target::Cloud => "cloud",
                Target::Edge => "edge",
                Target::Backup => "backup",
            };
            let a = match action {
                Action::Upload { .. } => "upload",
                Action::Download { .. } => "download",
                Action::Mirror { .. } => "mirror",
                Action::Delete { .. } => "delete",
            };
            format!("unsupported:{}:{}", a, t)
        }
    }
}

fn main() {
    let tasks = [
        Task {
            target: Target::Cloud,
            action: Action::Upload {
                files: 3,
                dry_run: false,
            },
        },
        Task {
            target: Target::Cloud,
            action: Action::Upload {
                files: 1,
                dry_run: true,
            },
        },
        Task {
            target: Target::Edge,
            action: Action::Download { name: "report.csv" },
        },
        Task {
            target: Target::Backup,
            action: Action::Mirror {
                path: "assets",
                verify: true,
            },
        },
        Task {
            target: Target::Backup,
            action: Action::Delete {
                name: "prod.log",
                force: true,
            },
        },
    ];

    for task in tasks.iter() {
        println!("{}", render(task));
    }
}

