#[derive(Debug)]
struct Record {
    name: String,
    age: u8,
    tags: Vec<String>,
}

fn parse_line(line: &str) -> Option<Record> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() != 3 {
        return None;
    }

    let name = parts[0].trim();
    if name.is_empty() {
        return None;
    }

    let age: u8 = parts[1].trim().parse().ok()?;

    let tags: Vec<String> = parts[2]
        .split(',')
        .map(|s| s.trim().to_string())
        .collect();

    Some(Record {
        name: name.to_string(),
        age,
        tags,
    })
}

fn valid(rec: &Record) -> bool {
    rec.age > 0 && !rec.tags.is_empty()
}

fn main() {
