enum Action {
    Start { label: &'static str },
    Io { source: &'static str, detail: &'static str },
    Warn(&'static str),
    Error { code: u16, detail: &'static str },
    Noop,
}

#[derive(Default)]
struct Counts {
    start: usize,
    io: usize,
    warn: usize,
    error: usize,
    noop: usize,
}

fn render(action: &Action, counts: &mut Counts) -> String {
    match action {
        Action::Start { label } => {
            counts.start += 1;
            format!("boot -> {}", label)
        }
        Action::Io { source, detail } => {
            counts.io += 1;
            format!("io -> {}: {}", source, detail)
        }
        Action::Warn(msg) => {
            counts.warn += 1;
            format!("warning -> {}", msg)
        }
        Action::Error { code, detail } => {
            counts.error += 1;
            if *code >= 500 {
                format!("fatal -> {}", detail)
            } else {
                format!("error -> {}", detail)
            }
        }
        Action::Noop => {
            counts.noop += 1;
            String::new()
        }
    }
}

fn main() {
    let actions = [
        Action::Start { label: "start warmup" },
        Action::Io { source: "cache", detail: "warmup" },
        Action::Io { source: "disk", detail: "flush" },
        Action::Warn("retrying sync"),
        Action::Error { code: 404, detail: "dropping packet" },
        Action::Noop,
    ];

    let mut counts = Counts::default();
    let mut lines = Vec::new();

    for action in &actions {
        lines.push(render(action, &mut counts));
    }

    lines.push(format!(
        "totals: start={} io={} warn={} error={} noop={}",
        counts.start, counts.io, counts.warn, counts.error, counts.noop
    ));

    println!("{}", lines.join("\n"));
}

