#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Done,
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::Open,
        "finish" => Status::InProgress,
        "reopen" => Status::Done,
        _ => status,
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "finish"),
        ("B", "start"),
        ("C", "start"),
        ("C", "finish"),
        ("D", "start"),
        ("D", "finish"),
        ("D", "reopen"),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in events {
        let current = tickets.get(id).copied().unwrap_or(Status::Open);
        tickets.insert(id, apply(current, event));
    }

    let mut open = 0;
    let mut in_progress = 0;
    let mut done = 0;

    for status in tickets.values() {
        match status {
            Status::Open => open += 1,
            Status::InProgress => in_progress += 1,
            Status::Done => done += 1,
        }
    }

    println!("open:{} in_progress:{} done:{}", open, in_progress, done);
