use std::fmt;

#[derive(Clone)]
struct Config {
    host: String,
    port: u16,
    timeout: u32,
    debug: bool,
}

impl fmt::Display for Config {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "host={}\nport={}\ntimeout={}\ndebug={}",
            self.host, self.port, self.timeout, self.debug
        )
    }
}

#[derive(Clone, Copy)]
struct PartialConfig {
    host: Option<&'static str>,
    port: Option<u16>,
    timeout: Option<u32>,
    debug: Option<bool>,
}

fn merge(defaults: Config, file: PartialConfig, env: PartialConfig, cli: PartialConfig) -> Config {
    let host = defaults.host;
    let port = defaults.port;
    let timeout = defaults.timeout;
    let debug = defaults.debug;

    let host = file.host.unwrap_or(host.as_str()).to_string();
    let host = cli.host.unwrap_or(env.host.unwrap_or(host.as_str())).to_string();

    let port = env.port.or(file.port).unwrap_or(port);
    let timeout = file.timeout.or(env.timeout).unwrap_or(timeout);
    let debug = file.debug.or(env.debug).or(cli.debug).unwrap_or(debug);

    Config {
        host,
        port,
        timeout,
        debug,
    }
}

fn main() {
    let defaults = Config {
        host: "localhost".to_string(),
        port: 8080,
        timeout: 30,
        debug: false,
    };

    let file = PartialConfig {
        host: Some("file.local"),
        port: Some(9000),
        timeout: Some(15),
        debug: None,
    };

    let env = PartialConfig {
        host: Some("env.local"),
        port: None,
        timeout: None,
        debug: Some(true),
    };

    let cli = PartialConfig {
        host: None,
        port: Some(7000),
