fn validate_line(i: usize, line: &str) -> Result<(), String> {
    let parts: Vec<&str> = line.split(',').collect();
    if parts.len() < 4 {
        return Err(format!("line {}: missing field count", i));
    }

    let age: u32 = parts[1]
