fn main() {
    let events = [
        "web|ok|deploy,canary",
        "ops|ok|backup,backup",
        "web|skip|legacy",
        "db|fail|restore",
        "qa|ok|smoke",
        "ops|ok|",
        "web|ok|deploy,blue",
    ];

    let grouped = build_report(&events);
    let lines: Vec<String> = grouped
        .into_iter()
        .map(|(team, count, tags)| format!("{} => {} [{}]", team, count, tags.join(", ")))
        .collect();

    print!("{}", lines.join("\n"));
}

fn build_report(events: &[&str]) -> Vec<(String, usize, Vec<String>)> {
    let mut by_team: BTreeMap<String, (usize, Vec<String>)> = BTreeMap::new();

    events
        .iter()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let team = parts.next()?;
            let status = parts.next()?;
            let tags = parts.next()?;
            Some((team, status, tags))
        })
        .filter(|(_, status, _)| *status != "fail")
        .for_each(|(team, _, tags)| {
            let entry = by_team.entry(team.to_string()).or_insert((0, Vec::new()));
            entry.0 += 1;
            entry.1.extend(
                tags.split(',')
                    .filter(|tag| !tag.is_empty())
                    .map(|tag| tag.to_string()),
            );
        });

    by_team
        .into_iter()
        .map(|(team, (count, mut tags))| {
            tags.sort();
            (team, count, tags)
        })
        .collect()
}

