fn valid_record(line: &str) -> Option<String> {
    let mut id = None;
    let mut kind = None;
    let mut score = None;

    for part in line.split(';') {
        let (k, v) = part.split_once('=')?;
        match k {
            "id" => id = Some(v.to_string()),
            "kind" => kind = Some(v),
            "score" => score = v.parse::<u32>().ok(),
            _ => {}
        }
    }

    let id = id?;
    let kind = kind?;
    let score = score.unwrap_or(0);

    if id.is_empty() {
        return None;
    }

    if kind != "alpha" && kind != "beta" {
        return None;
    }

    if score > 100 {
        return None;
    }

    Some(id)
}

fn main() {
    let input = [
        "id=A1;kind=alpha;score=42",
        "id=B2;kind=beta",
        "id=C3;kind=gamma;score=9",
        "id=D4;kind=beta;score=100;note=ok",
        "id=;kind=alpha;score=7",
        "id=E5;kind=alpha;score=120",
    ];

    let ids: Vec<String> = input.iter().filter_map(|line| valid_record(line)).collect();
    println!("ok: {}", ids.join(","));
}

