use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn label(self) -> &'static str {
        match self {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Blocked => "blocked",
            Status::Closed => "closed",
        }
    }
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "block" => Status::Blocked,
        "resume" => Status::Open,
        "close" => Status::Closed,
        "reopen" => Status::Open,
        _ => status,
    }
}

fn main() {
    let log = [
        ("T1", "start"),
        ("T1", "block"),
        ("T1", "resume"),
        ("T1", "close"),
        ("T2", "start"),
        ("T2", "block"),
        ("T2", "resume"),
        ("T3", "close"),
        ("T3", "reopen"),
        ("T3", "close"),
    ];

    let mut items: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in log {
        let current = *items.get(id).unwrap_or(&Status::Open);
        let next = apply(current, event);
        items.insert(id, next);
    }

    let mut counts: BTreeMap<&'static str, usize> = BTreeMap::new();
    for status in [Status::Open, Status::InProgress, Status::Blocked, Status::Closed] {
        counts.insert(status.label(), 0);
    }
    for status in items.values() {
        *counts.get_mut(status.label()).unwrap() += 1;
    }

    println!("open: {}", counts["open"]);
    println!("in_progress: {}", counts["in_progress"]);
    println!("blocked: {}", counts["blocked"]);
    println!("closed: {}", counts["closed"]);
    println!("items:");
    for (id, status) in &items {
        println!("{}={}", id, status.label());
    }
}

enum Action {
    Read,
    Write,
    Delete,
}

enum Event<'a> {
    Allow { path: &'a str, actions: Vec<Action> },
    Deny { path: &'a str, actions: Vec<Action> },
    Audit { name: &'a str, critical: bool },
}

fn action_name(a: &Action) -> &'static str {
    match a {
        Action::Read => "read",
        Action::Write => "write",
        Action::Delete => "delete",
    }
}

fn format_actions(actions: &[Action]) -> String {
    let mut out = String::new();
    for (i, a) in actions.iter().enumerate() {
        if i > 0 {
            out.push(',');
        }
        out.push_str(action_name(a));
    }
    out
}

fn render(event: &Event) -> String {
    match event {
        Event::Allow { path, actions } => {
            format!("allow: {} [{}]", path, format_actions(actions))
        }
        Event::Deny { path, actions } => {
            format!("deny: {} [{}]", path, format_actions(actions))
        }
        Event::Audit { name, critical } => {
            if *critical {
                format!("audit: {}", name)
            } else {
                format!("audit: {} (critical)", name)
            }
        }
    }
}

fn main() {
    let events = vec![
        Event::Allow {
            path: "/srv/archive",
            actions: vec![Action::Read, Action::Write],
        },
        Event::Deny {
            path: "/tmp",
            actions: vec![Action::Delete],
        },
        Event::Audit {
            name: "deploy",
            critical: true,
        },
        Event::Audit {
            name: "login",
            critical: false,
        },
        Event::Allow {
            path: "/var/log",
            actions: vec![Action::Read],
        },
        Event::Deny {
            path: "/etc/shadow",
            actions: vec![Action::Read, Action::Write],
        },
    ];

    let mut allow = 0;
    let mut deny = 0;
    let mut audit = 0;

    for event in &events {
        println!("{}", render(event));
        match event {
            Event::Allow { .. } => allow += 1,
            Event::Deny { .. } => audit += 1,
            Event::Audit { .. } => deny += 1,
        }
    }

    println!("summary allow={} deny={} audit={}", allow, deny, audit);
}

