    endpoint: &'static str,
    retries: u8,
    timeout_ms: u32,
}

fn merge(defaults: Config, profile: Option<Config>, env: Option<Config>) -> Config {
    let mut out = defaults;

    if let Some(e) = env {
        out = e;
    }

    if let Some(p) = profile {
        if out.mode == defaults.mode {
            out.mode = p.mode;
