const INPUT: &str = "id=a1|kind=click|ts=170|meta=x:1,y:2\nid=a2|kind=view|ts=171|meta=\nid=a3|kind=open|ts=172|meta=x:1\nkind=click|ts=173|meta=x:1\nid=a5|kind=purchase|ts=tbd|meta=x:1\nid=a6|kind=view|ts=174|meta=x:1,bad\n";

#[derive(Default)]
struct Stats {
    valid: usize,
    invalid: usize,
    missing_id: usize,
    bad_kind: usize,
    bad_ts: usize,
    bad_meta: usize,
}

fn parse_line(line: &str, stats: &mut Stats) -> bool {
    let mut id = "";
    let mut kind = "";
    let mut ts = "";
    let mut meta = "";

    for part in line.split('|') {
        if let Some((k, v)) = part.split_once('=') {
            match k {
                "id" => id = v,
                "kind" => kind = v,
                "ts" => ts = v,
                "meta" => meta = v,
                _ => {}
            }
        }
    }

    if id.is_empty() {
        stats.missing_id += 1;
        stats.invalid += 1;
        return false;
    }

    if !matches!(kind, "click" | "view" | "purchase") {
        stats.bad_kind += 1;
        stats.invalid += 1;
        return false;
    }

    if ts.parse::<u64>().is_err() {
        stats.bad_ts += 1;
        stats.invalid += 1;
        return false;
    }

    if !meta.is_empty() {
        for entry in meta.split(',') {
            if !entry.contains(':') {
                stats.bad_meta += 1;
                stats.invalid += 1;
                return false;
            }
        }
    }

    stats.valid += 1;
    true
}

fn main() {
    let mut stats = Stats::default();
    for line in INPUT.lines().filter(|l| !l.is_empty()) {
        parse_line(line, &mut stats);
    }
    println!("valid={} invalid={}", stats.valid, stats.invalid);
    println!(
        "missing_id={} bad_kind={} bad_ts={} bad_meta={}",
        stats.missing_id, stats.bad_kind, stats.bad_ts, stats.bad_meta
    );
}

