        Event::Start(_) => Status::InProgress,
        Event::Block(_) => Status::Blocked,
        Event::Unblock(_) => Status::Open,
        Event::Resolve(_) => Status::Closed,
        Event::Reopen(_) => status.unwrap_or(Status::Open),
    }
}

fn ticket_id(event: Event<'_>) -> &'_ str {
    match event {
        Event::Opened(id)
        | Event::Start(id)
        | Event::Block(id)
        | Event::Unblock(id)
        | Event::Resolve(id)
        | Event::Reopen(id) => id,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "open",
        Status::InProgress => "in_progress",
        Status::Blocked => "blocked",
        Status::Closed => "closed",
    }
}

fn main() {
    let events = [
        Event::Opened("A"),
        Event::Start("A"),
        Event::Block("A"),
        Event::Unblock("A"),
        Event::Resolve("A"),
        Event::Opened("B"),
        Event::Block("B"),
        Event::Unblock("B"),
        Event::Opened("C"),
        Event::Resolve("C"),
        Event::Reopen("C"),
        Event::Start("C"),
        Event::Resolve("C"),
    ];

    let mut states: BTreeMap<&str, Status> = BTreeMap::new();
    for event in events {
        let id = ticket_id(event);
        let next = apply(states.get(id).copied(), event);
        states.insert(id, next);
    }

    let mut lines = Vec::new();
    for (id, status) in states {
        lines.push(format!("{}:{}", id, label(status)));
    }
    println!("{}", lines.join("\n"));
}

