fn parse_hhmm(s: &str) -> u32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<u32>().unwrap() * 60 + m.parse::<u32>().unwrap()
}

fn fmt_hhmm(mins: u32) -> String {
    format!("{:02}:{:02}", mins / 60, mins % 60)
}

fn overlaps(a_start: u32, a_end: u32, b_start: u32, b_end: u32) -> bool {
    let starts_inside = b_start >= a_start && b_start <= a_end;
    let ends_inside = b_end >= a_start && b_end <= a_end;
    starts_inside || ends_inside
}

fn main() {
    let requests = [
        (1, "09:00", "10:00"),
        (2, "10:00", "11:00"),
        (3, "09:30", "09:45"),
        (4, "10:30", "11:30"),
        (5, "11:30", "12:00"),
    ];

    let mut accepted: Vec<(u32, u32, u32)> = Vec::new();
    let mut out = Vec::new();

    for &(id, start_s, end_s) in &requests {
        let start = parse_hhmm(start_s);
        let end = parse_hhmm(end_s);

        let mut conflict = None;
        for &(other_id, other_start, other_end) in &accepted {
            if overlaps(other_start, other_end, start, end) {
                conflict = Some((other_id, other_start, other_end));
                break;
            }
        }

        match conflict {
            Some((other_id, other_start, other_end)) => out.push(format!(
                "rejected #{} [{}-{}] conflicts with #{} [{}-{}]",
                id,
                fmt_hhmm(start),
                fmt_hhmm(end),
                other_id,
                fmt_hhmm(other_start),
                fmt_hhmm(other_end)
            )),
            None => {
                accepted.push((id, start, end));
                out.push(format!(
                    "accepted #{} [{}-{}]",
                    id,
                    fmt_hhmm(start),
                    fmt_hhmm(end)
                ));
            }
        }
    }

    println!("{}", out.join("\n"));
}

