fn validate_line(line: &str) -> Result<(), String> {
    let parts: Vec<&str> = line.split(';').collect();
    if parts.len() < 3 {
        return Err("wrong field count".to_string());
    }

    let mut seen_id = false;
    let mut seen_name = false;
    let mut seen_age = false;

    for part in parts {
        let mut kv = part.splitn(2, '=');
        let key = kv.next().unwrap_or("");
        let value = kv.next().unwrap_or("");

        match key {
            "id" => {
                seen_id = true;
                if value.is_empty() || !value.chars().all(|c| c.is_ascii_digit()) {
                    return Err("bad id".to_string());
                }
            }
            "name" => {
                seen_name = true;
                if value.is_empty() {
                    return Err("missing name".to_string());
                }
            }
            "age" => {
                seen_age = true;
                if value.parse::<u8>().is_err() {
                    return Err("bad age".to_string());
                }
            }
            _ => return Err("unknown field".to_string()),
        }
    }

    if !seen_id {
        return Err("missing id".to_string());
    }
    if !seen_name {
        return Err("missing name".to_string());
    }
    if !seen_age {
        return Err("missing age".to_string());
    }

    Ok(())
}

fn main() {
    let input = "id=1;name=Ana;age=30\nid=2;id=3;name=Bob;age=20\nid=4;name=Cy;age=two\nid=5;age=40\nid=6;name=Dee";

    let mut valid = 0usize;
    let mut invalid = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        match validate_line(line) {
            Ok(()) => valid += 1,
            Err(msg) => invalid.push(format!("line {}: {}", idx + 1, msg)),
        }
    }

    println!("valid: {}", valid);
    println!("invalid:");
    for msg in invalid {
        println!("{}", msg);
    }
}

