use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    Waiting,
    InProgress,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Waiting => "waiting",
            State::InProgress => "in_progress",
            State::Closed => "closed",
        }
    }
}

fn main() {
    let events = [
        "A:create",
        "A:start",
        "A:close",
        "A:reopen",
        "A:close",
        "B:create",
        "B:start",
        "B:reopen",
        "C:create",
        "C:start",
        "C:close",
        "C:reopen",
        "C:start",
        "C:close",
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for event in events {
        let (id, action) = event.split_once(':').unwrap();
        let current = tickets.get(id).copied();
        let next = match action {
            "create" => Some(State::Waiting),
            "start" => Some(State::InProgress),
            "close" => Some(State::Closed),
            "reopen" => Some(match current {
                Some(State::Closed) => State::InProgress,
                Some(state) => state,
                None => State::Waiting,
            }),
            _ => current,
        };
        if let Some(state) = next {
            tickets.insert(id, state);
        }
    }

    let mut lines = Vec::new();
    for (id, state) in tickets {
        lines.push(format!("{}:{}", id, state.as_str()));
    }
    println!("{}", lines.join("\n"));
}

