fn score(action: &str) -> Option<i32> {
    match action {
        "open" => Some(3),
        "close" => Some(5),
        "merge" => Some(8),
        _ => None,
    }
}

fn main() {
    let input = r#"
# activity stream
user=ana;action=open;tags=alpha,beta
user=bob;action=merge;tags=beta,alpha
user=ana;action=close;tags=alpha
user=cid;action=open;tags=alpha,beta
user=bob;action=close;tags=alpha,beta,beta
user=ana;action=merge;tags=beta
user=bob;action=open;tags=alpha,beta,gamma
user=ana;action=close;tags=alpha,beta
user=bob;action=merge;tags=
user=ana;action=ignore;tags=alpha,beta
user=bob;action=close;tags=alpha, beta
user=ana;action=open;tags=alpha,beta;extra=1
junk
"#;

    let allowed_users: BTreeSet<&str> = ["ana", "bob"].into_iter().collect();
    let required_tags: BTreeSet<&str> = ["alpha", "beta"].into_iter().collect();

    let mut totals: BTreeMap<String, i32> = BTreeMap::new();

    for line in input.lines().map(str::trim).filter(|line| !line.is_empty() && !line.starts_with('#')) {
        let mut user = None;
        let mut action = None;
        let mut tags: BTreeSet<&str> = BTreeSet::new();

        for part in line.split(';') {
            if let Some((key, value)) = part.split_once('=') {
                match key {
                    "user" => user = Some(value),
                    "action" => action = Some(value),
                    "tags" => tags.extend(value.split(',')),
                    _ => {}
                }
            }
        }

        if let (Some(user), Some(action)) = (user, action) {
            if allowed_users.contains(user) && tags.iter().any(|t| required_tags.contains(*t)) {
                if let Some(points) = score(action) {
                    *totals.entry(user.to_string()).or_insert(0) += points;
                }
            }
        }
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));

    let output = rows
        .into_iter()
        .map(|(user, total)| format!("{user}:{total}"))
        .collect::<Vec<_>>()
        .join("\n");

    println!("{output}");
