fn merge(base: Config, overlay: Config) -> Config {
    Config {
        host: if overlay.host.is_some() { overlay.host } else { base.host },
        port: overlay.port.or(base.port),
        timeout_ms: overlay.timeout_ms.or(base.timeout_ms),
        retries: overlay.retries.or(base.retries),
    }
}

fn main() {
    let defaults = Config {
        host: Some("localhost"),
        port: Some(8080),
        timeout_ms: Some(5000),
        retries: Some(2),
    };

    let profile = Config {
