    println!("host={}", merged.host.unwrap_or("-"));
    println!("port={}", merged.port.unwrap_or(0));
    println!("timeout_ms={}", merged.timeout_ms.unwrap_or(0));
    println!("retries={}", merged.retries.unwrap_or(0));
}

fn parse_line(line: &str) -> Result<(&str, i32, &str), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return Err("malformed field count".to_string());
    }

    let id = parts[0];
    if id.is_empty() || !id.chars().all(|c| c.is_ascii_alphanumeric()) {
        return Err(format!("invalid id {}", id));
    }

    let qty: i32 = parts[1].parse().map_err(|_| "invalid qty".to_string())?;
    if qty < 0 {
        return Err("qty must be > 0".to_string());
    }

    let category = parts[2];
    match category {
        "tools" | "parts" | "supplies" => {}
        _ => return Err(format!("invalid category {}", category)),
    }

    Ok((id, qty, category))
}

fn main() {
    let input = "A12|5|tools\nB3|0|parts\nA12|2|tools\nC7|9\nD9|4|snacks\nE5|3|supplies|extra";
    let mut seen = Vec::new();
    let mut valid = Vec::new();
    let mut invalid = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        match parse_line(line) {
            Ok((id, _qty, _category)) => {
                if seen.contains(&id) {
                    invalid.push(format!("line {}: duplicate id {}", idx + 1, id));
                } else {
                    seen.push(id);
                    valid.push(id.to_string());
                }
            }
