enum Event {
    Http(u16),
    Task { ok: bool, retries: u8 },
    Cache(Option<&'static str>),
    Feature { enabled: bool, rollout: u8 },
    Shutdown(bool),
}

#[derive(Clone, Copy)]
enum Bucket {
    Ok,
    Warn,
    Err,
    Skip,
}

fn classify(event: &Event) -> Bucket {
    match event {
        Event::Http(code) => match code {
            200..=299 => Bucket::Ok,
            300..=399 => Bucket::Warn,
            400..=599 => Bucket::Warn,
            _ => Bucket::Skip,
        },
        Event::Task { ok, retries } => {
            if *ok {
                Bucket::Ok
            } else if *retries > 0 {
                Bucket::Skip
            } else {
                Bucket::Err
            }
        }
        Event::Cache(value) => {
            if value.is_some() {
                Bucket::Ok
            } else {
                Bucket::Err
            }
        }
        Event::Feature { enabled, rollout } => {
            if *enabled && *rollout == 100 {
                Bucket::Ok
            } else if *enabled {
                Bucket::Warn
            } else {
                Bucket::Skip
            }
        }
        Event::Shutdown(clean) => {
            if *clean {
                Bucket::Warn
            } else {
                Bucket::Err
            }
        }
    }
}

fn main() {
    let events = [
        Event::Http(204),
        Event::Http(302),
        Event::Http(404),
        Event::Http(503),
        Event::Task { ok: true, retries: 0 },
        Event::Task { ok: false, retries: 2 },
        Event::Task { ok: false, retries: 0 },
        Event::Cache(Some("hot")),
        Event::Cache(None),
        Event::Feature { enabled: true, rollout: 100 },
        Event::Feature { enabled: true, rollout: 25 },
        Event::Feature { enabled: false, rollout: 0 },
        Event::Shutdown(true),
        Event::Shutdown(false),
        Event::Http(150),
    ];

    let mut ok = 0;
    let mut warn = 0;
    let mut err = 0;
    let mut skip = 0;

    for event in &events {
        match classify(event) {
            Bucket::Ok => ok += 1,
            Bucket::Warn => warn += 1,
            Bucket::Err => err += 1,
            Bucket::Skip => skip += 1,
        }
    }

    println!("ok={}", ok);
    println!("warn={}", warn);
    println!("err={}", err);
    println!("skip={}", skip);
}

