fn summarize(input: &str) -> String {
    input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let id = parts.next()?.parse::<u32>().ok()?;
            let active = parts.next()? == "active";
            let tag = parts.next()?;
            if active && tag != "skip" {
                Some(format!("{}:{}", id, tag))
            } else {
                None
            }
        })
        .take(3)
        .collect::<Vec<_>>()
        .join(",")
}

