enum Mode {
    Copy { overwrite: bool },
    Move,
    Delete { permanent: bool },
    Tag { tags: Vec<&'static str> },
    Status { verbose: bool },
    Batch { strict: bool, items: Vec<Cmd> },
}

enum Cmd {
    File { src: &'static str, dst: &'static str, mode: Mode },
    Target { name: &'static str, mode: Mode },
}

fn render(cmd: &Cmd) -> String {
    match cmd {
        Cmd::File { src, dst, mode } => match mode {
            Mode::Copy { overwrite } => {
                let flag = if *overwrite { " [replace]" } else { " [skip]" };
                format!("COPY {src} -> {dst}{flag}")
            }
            Mode::Move => format!("MOVE {src} -> {dst}"),
            Mode::Delete { permanent } => {
                if *permanent {
                    format!("DELETE {src} [purge]")
                } else {
                    format!("DELETE {src} [trash]")
                }
            }
            Mode::Tag { tags } => format!("TAG {src} {}", tags.join(" ")) ,
            Mode::Status { verbose } => {
                if *verbose {
                    format!("STATUS {src} [verbose]")
                } else {
                    format!("STATUS {src}")
                }
            }
            Mode::Batch { strict, items } => {
                let mut out = format!("BATCH {}{}", items.len(), if *strict { " [strict]" } else { "" });
                for item in items {
                    out.push_str("\n  ");
                    out.push_str(&render(item));
                }
                out
            }
        },
        Cmd::Target { name, mode } => match mode {
            Mode::Copy { overwrite } => {
                let flag = if *overwrite { " [replace]" } else { " [skip]" };
                format!("COPY {name} -> {name}{flag}")
            }
            Mode::Move => format!("MOVE {name} -> {name}"),
            Mode::Delete { permanent } => {
                if *permanent {
                    format!("DELETE {name} [purge]")
                } else {
                    format!("DELETE {name} [trash]")
                }
            }
            Mode::Tag { tags } => format!("TAG {name} {}", tags.join(" ")),
            Mode::Status { verbose } => {
                if *verbose {
                    format!("STATUS {name} [verbose]")
                } else {
                    format!("STATUS {name} [verbose]")
                }
            }
            Mode::Batch { strict, items } => {
                let mut out = format!("BATCH {}", items.len());
                if *strict {
                    out.push_str(" [strict]");
                }
                for item in items {
                    out.push_str("\n");
                    out.push_str(&render(item));
                }
                out
            }
        },
    }
}

fn main() {
    let cmds = vec![
        Cmd::File {
            src: "src.txt",
            dst: "out.txt",
            mode: Mode::Copy { overwrite: true },
        },
        Cmd::File {
            src: "archive.zip",
            dst: "backup/",
            mode: Mode::Move,
        },
        Cmd::File {
            src: "old.log",
            dst: "_",
            mode: Mode::Delete { permanent: false },
        },
        Cmd::Target {
            name: "report.md",
            mode: Mode::Tag {
                tags: vec!["+urgent", "+client"],
            },
        },
        Cmd::Target {
            name: "remote",
            mode: Mode::Status { verbose: true },
        },
        Cmd::Target {
            name: "ops",
            mode: Mode::Batch {
                strict: true,
                items: vec![
                    Cmd::File {
                        src: "a",
                        dst: "b",
                        mode: Mode::Copy { overwrite: false },
                    },
                    Cmd::Target {
                        name: "svc",
                        mode: Mode::Status { verbose: false },
                    },
                ],
            },
        },
    ];

    let rendered: Vec<String> = cmds.iter().map(render).collect();
    print!("{}", rendered.join("\n"));
}

