#[derive(Clone, Debug, Default)]
struct Config {
    mode: Option<&'static str>,
    retry: Option<u32>,
    timeout: Option<u32>,
    features: Vec<&'static str>,
}

fn merge(defaults: Config, file: Config, env: Config, cli: Config) -> Config {
    let mode = defaults.mode.or(file.mode).or(env.mode).or(cli.mode);
    let retry = defaults.retry.or(file.retry).or(env.retry).or(cli.retry);
    let timeout = defaults.timeout.or(file.timeout).or(env.timeout).or(cli.timeout);

    let mut features = Vec::new();
    features.extend(defaults.features);
    if !file.features.is_empty() {
        features = file.features;
    }
    if !env.features.is_empty() {
        features.extend(env.features);
    }
    if !cli.features.is_empty() {
        features = cli.features;
    }

    Config { mode, retry, timeout, features }
}

fn render(cfg: &Config) -> String {
    let mut uniq = BTreeSet::new();
    for f in &cfg.features {
        uniq.insert(*f);
    }
    let features = uniq.into_iter().collect::<Vec<_>>().join(",");
    format!(
        "mode={}\nretry={}\ntimeout={}\nfeatures={}",
        cfg.mode.unwrap_or("unset"),
        cfg.retry.unwrap_or(0),
        cfg.timeout.unwrap_or(0),
        features
    )
}

