use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Todo,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn label(&self) -> &'static str {
        match self {
            Status::Todo => "Todo",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

#[derive(Clone)]
struct Ticket {
    status: Status,
    owner: Option<&'static str>,
    blocked: bool,
    reopenable: bool,
}

impl Ticket {
    fn new() -> Self {
        Self {
            status: Status::Todo,
            owner: None,
            blocked: false,
            reopenable: false,
        }
    }
}

enum Event {
    Start(&'static str),
    Block,
    Unblock,
    Resolve,
    Reopen,
    Transfer(&'static str),
}

fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Start(owner) => {
            ticket.owner = Some(owner);
            ticket.status = Status::InProgress;
            ticket.blocked = false;
        }
        Event::Block => {
            ticket.status = Status::Blocked;
            ticket.blocked = true;
        }
        Event::Unblock => {
            ticket.blocked = false;
        }
        Event::Resolve => {
            ticket.status = Status::Closed;
            ticket.reopenable = false;
            ticket.blocked = false;
        }
        Event::Reopen => {
            ticket.status = Status::Todo;
            ticket.reopenable = true;
        }
        Event::Transfer(owner) => {
            ticket.owner = Some(owner);
        }
    }
}

fn main() {
    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    let events = [
        ("A", Event::Start("amy")),
        ("A", Event::Resolve),
        ("B", Event::Start("ben")),
        ("B", Event::Transfer("bob")),
        ("B", Event::Resolve),
        ("B", Event::Reopen),
        ("C", Event::Start("cora")),
        ("C", Event::Block),
        ("C", Event::Transfer("none")),
        ("C", Event::Unblock),
        ("C", Event::Block),
    ];

    for (id, event) in events {
        let ticket = tickets.entry(id).or_insert_with(Ticket::new);
        apply(ticket, event);
    }

    let mut lines = Vec::new();
    for (id, t) in tickets {
        let owner = t.owner.unwrap_or("none");
        lines.push(format!(
            "{}: {} [owner={}, blocked={}, reopenable={}]",
            id,
            t.status.label(),
            owner,
            t.blocked,
            t.reopenable
        ));
    }
    print!("{}", lines.join("\n"));
}

