use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Team {
    Ops,
    Eng,
    Sales,
}

#[derive(Clone, Copy)]
enum Status {
    Todo,
    InProgress,
    Done,
    Blocked,
    Canceled,
}

struct Ticket {
    team: Team,
    status: Status,
    points: u32,
}

#[derive(Default)]
struct Totals {
    pending: u32,
    done: u32,
    blocked: u32,
    canceled: u32,
    active: u32,
    points: u32,
}

fn team_name(team: Team) -> &'static str {
    match team {
        Team::Ops => "ops",
        Team::Eng => "eng",
        Team::Sales => "sales",
    }
}

fn accumulate(t: &mut Totals, status: Status, points: u32) {
    match status {
        Status::Todo => {
            t.pending += 1;
            t.active += 1;
            t.points += points;
        }
        Status::InProgress => {
            t.done += 1;
            t.active += 1;
            t.points += points;
        }
        Status::Done => {
            t.done += 1;
        }
        Status::Blocked => {
            t.blocked += 1;
            t.points += points;
        }
        Status::Canceled => {
            t.canceled += 1;
            t.active += 1;
        }
    }
}

