#[derive(Clone, Debug)]
struct Config {
    retries: Option<u8>,
    timeout: Option<u16>,
    cache: Option<bool>,
    endpoint: Option<&'static str>,
    features: Vec<&'static str>,
}

impl Config {
    fn merged(mut self, other: &Config) -> Config {
        if self.retries.is_none() {
            self.retries = other.retries;
        }
        if self.timeout.is_none() {
            self.timeout = other.timeout;
        }
        if self.cache.is_none() {
            self.cache = other.cache;
        }
        if self.endpoint.is_none() {
            self.endpoint = other.endpoint;
        }
        if self.features.is_empty() {
            self.features = other.features.clone();
        }
        self
    }
}

fn main() {
    let defaults = Config {
        retries: Some(3),
        timeout: Some(30),
        cache: Some(true),
        endpoint: Some("https://default"),
        features: vec!["base", "metrics"],
    };

    let profile = Config {
        retries: Some(5),
        timeout: Some(20),
        cache: None,
        endpoint: Some("https://profile"),
        features: vec!["audit"],
