#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let bookings = [
        Booking { id: "A", start: 60, end: 120 },
        Booking { id: "B", start: 120, end: 180 },
        Booking { id: "C", start: 90, end: 100 },
        Booking { id: "D", start: 180, end: 180 },
        Booking { id: "E", start: 150, end: 160 },
        Booking { id: "F", start: 180, end: 210 },
        Booking { id: "G", start: 210, end: 240 },
    ];

    let mut conflicts = Vec::new();
    let mut rejected = 0usize;

    for i in 0..bookings.len() {
        let current = bookings[i];
        let mut bad = false;

        for j in 0..i {
            let prior = bookings[j];
            if overlaps(current, prior) {
                bad = true;
                conflicts.push(format!("{} vs {}", current.id, prior.id));
                break;
            }
        }

        if bad {
            rejected += 1;
        }
    }

    println!("valid bookings: {}", bookings.len() - rejected);
    println!("rejected bookings: {}", rejected);
    println!("conflicts:");
    for line in conflicts {
        println!("{}", line);
    }
}

steps.find:
fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

steps.replace:
fn overlaps(a: Booking, b: Booking) -> bool {
    a.start < b.end && b.start < a.end
}

steps.find:
for i in 0..bookings.len() {
    let current = bookings[i];
    let mut bad = false;

    for j in 0..i {
        let prior = bookings[j];
        if overlaps(current, prior) {
            bad = true;
            conflicts.push(format!("{} vs {}", current.id, prior.id));
            break;
        }
    }

    if bad {
        rejected += 1;
    }
}

steps.replace:
for i in 0..bookings.len() {
    let current = bookings[i];
    if current.start >= current.end {
        rejected += 1;
        continue;
    }
    let mut bad = false;

    for j in 0..i {
        let prior = bookings[j];
        if prior.start >= prior.end {
            continue;
        }
        if overlaps(current, prior) {
            bad = true;
            let (left, right) = if current.id < prior.id {
                (current.id, prior.id)
            } else {
                (prior.id, current.id)
            };
            conflicts.push(format!("{} vs {}", left, right));
            break;
        }
    }

    if bad {
        rejected += 1;
    }
}

conflicts.sort();

