use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Closed,
    Reopened,
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
}

fn apply_event(current: Option<State>, event: Event) -> Option<State> {
    use Event::*;
    use State::*;

    match (current, event) {
        (None, Create) => Some(Open),
        (Some(Open), Start) => Some(InProgress),
        (Some(Blocked), Unblock) => Some(InProgress),
        (Some(InProgress), Block) => Some(Blocked),
        (Some(InProgress), Resolve) | (Some(Blocked), Resolve) => Some(Closed),
        (Some(Closed), Reopen) => Some(Reopened),
        (Some(Reopened), Start) => Some(InProgress),
        (Some(Reopened), Resolve) => Some(Closed),
        (state, _) => state,
    }
}

fn state_name(state: State) -> &'static str {
    match state {
        State::Open => "Open",
        State::InProgress => "InProgress",
        State::Blocked => "Blocked",
        State::Closed => "Closed",
        State::Reopened => "Reopened",
    }
}

fn main() {
    let events = [
        ("A100", Event::Create),
        ("A100", Event::Start),
        ("A100", Event::Resolve),
        ("A101", Event::Create),
        ("A101", Event::Start),
        ("A101", Event::Resolve),
        ("A101", Event::Reopen),
        ("A102", Event::Create),
        ("A102", Event::Start),
        ("A102", Event::Block),
        ("A102", Event::Unblock),
        ("A103", Event::Create),
        ("A103", Event::Resolve),
        ("A103", Event::Start),
        ("A103", Event::Resolve),
        ("A102", Event::Resolve),
    ];

    let mut states: BTreeMap<&str, Option<State>> = BTreeMap::new();

    for (id, event) in events {
        let current = states.get(id).copied().flatten();
        let next = apply_event(current, event);
        states.insert(id, next);
    }

    let mut lines = Vec::new();
    for (id, state) in states {
        if let Some(state) = state {
            lines.push(format!("{}: {}", id, state_name(state)));
        }
    }

    print!("{}", lines.join("\n"));
}

enum Channel {
    Email { urgent: bool, category: &'static str },
    Sms { urgent: bool, category: &'static str },
    Chat { room: &'static str, urgent: bool },
}

struct Message {
    channel: Channel,
}

fn is_ops(msg: &Message) -> bool {
    match &msg.channel {
        Channel::Email { category, .. } | Channel::Sms { category, .. } => *category == "ops",
        Channel::Chat { room, .. } => room.starts_with("ops-"),
    }
}

fn is_marketing(msg: &Message) -> bool {
    match &msg.channel {
        Channel::Email { category, .. } | Channel::Sms { category, .. } => *category == "marketing",
        Channel::Chat { room, .. } => room == &"campaigns",
    }
}

fn is_urgent(msg: &Message, kind: &str) -> bool {
    match (&msg.channel, kind) {
        (Channel::Email { urgent, .. }, "email") => *urgent,
        (Channel::Sms { urgent, .. }, "sms") => *urgent,
        (Channel::Chat { urgent, .. }, "chat") => *urgent,
        _ => false,
    }
}

fn main() {
    let messages = vec![
        Message { channel: Channel::Email { urgent: true, category: "ops" } },
        Message { channel: Channel::Email { urgent: true, category: "marketing" } },
        Message { channel: Channel::Sms { urgent: false, category: "ops" } },
        Message { channel: Channel::Sms { urgent: false, category: "marketing" } },
        Message { channel: Channel::Chat { room: "ops-war", urgent: true } },
        Message { channel: Channel::Chat { room: "ops-daily", urgent: false } },
    ];

    let ops = messages.iter().filter(|m| is_ops(m)).count();
    let marketing = messages.iter().filter(|m| is_marketing(m)).count();
    let all = messages.len();
    let email_urgent = messages.iter().filter(|m| is_urgent(m, "email")).count();
    let chat_urgent = messages.iter().filter(|m| is_urgent(m, "chat")).count();
    let sms_urgent = messages.iter().filter(|m| is_urgent(m, "sms")).count();
    let promos = messages.iter().filter(|m| is_marketing(m)).count();
    let system = messages.iter().filter(|m| is_ops(m) && !is_marketing(m)).count();

    println!("ops=>{}", ops);
    println!("marketing=>{}", marketing);
    println!("all=>{}", all);
    println!("email urgent=>{}", email_urgent);
    println!("chat urgent=>{}", chat_urgent);
    println!("sms urgent=>{}", sms_urgent);
    println!("promos=>{}", promos);
    println!("system=>{}", system);
}

use std::collections::BTreeMap;

fn merge_layers(layers: &[&str]) -> BTreeMap<String, String> {
    let mut out = BTreeMap::new();
    for layer in layers {
        for line in layer.lines() {
            let line = line.trim();
            if line.is_empty() || line.starts_with('#') {
                continue;
            }
            if let Some((k, v)) = line.split_once('=') {
                out.insert(k.trim().to_string(), v.trim().to_string());
            }
        }
    }
    out
}

fn main() {
    let defaults = "host=localhost
port=5432
tls=false
mode=release";

    let env = "port=8080
tls=true";

    let cli = "host=db.local
mode=debug";

    let merged = merge_layers(&[defaults, env, cli]);
    for (k, v) in merged {
        println!("{}={}", k, v);
    }
}
